-- ================================================
-- EasyTech Data Migration from Old Server
-- 10 clients, 10 categories, 93 products
-- ================================================
USE easytech_v2;

ALTER TABLE users ADD COLUMN IF NOT EXISTS phone VARCHAR(50) NULL;
ALTER TABLE users ADD COLUMN IF NOT EXISTS address TEXT NULL;
ALTER TABLE users ADD COLUMN IF NOT EXISTS location VARCHAR(255) NULL;
ALTER TABLE users ADD COLUMN IF NOT EXISTS avatar_url TEXT NULL;

-- ========== USERS/CLIENTS ==========

-- ========== CATEGORIES ==========
CREATE TABLE IF NOT EXISTS categories (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  name_ar VARCHAR(255) NULL,
  image_url TEXT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ========== PRODUCTS ==========
CREATE TABLE IF NOT EXISTS products (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  name_ar VARCHAR(255) NULL,
  description TEXT NULL,
  price DECIMAL(12,2) DEFAULT 0,
  category_id INT NULL,
  image_url TEXT NULL,
  images JSON NULL,
  is_active TINYINT(1) DEFAULT 1,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_category (category_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Migration complete!