INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30089, 'ET-C7', 'ET-C7', 'ET-C7 تقنية بصمة راحة اليد جسم الكالون محفور من شريحة صلبة بتقنية ال CNC نحت دقيق ومتين بتقنية CNC، تصميم مبتكر، شكل جديد لا تلامس، استشعار بالرادار، تمييز تلقائي وفتح تلقائي تقنية التميز بين الوجوه الحقيقية وبين الصور والفيديوهات وقوالب الجبس وأقنعة المحاكاة بفعالية، إلخ. مراقبة نشطة في الوقت الفعلي، اتصال داخلي مرئي عن بُعد، فتح تلقائي للهواتف المحمولة رؤية ليلية مدمجة بالأشعة تحت الحمراء، رؤية واضحة في الليل عدسة عين القطة فائقة الاتساع، مجال رؤية أوسع، رؤية أوضح موصفات المنتج : مادة المنتج: ألومنيوم طيران مصدر طاقة التشغيل: بطارية ليثيوم أشباه موصلات لجمع بصمات الأصابع سعة المستخدم: ٣٠٠ وجه/بصمة إصبع/كلمة مرور/بطاقة. مناسب للأبواب من نوع: أبواب حديدية/أبواب نحاسية/أبواب مضادة للسرقة، إلخ. تقنية السطح: الأكسدة نوع أسطوانة القفل: مستوى C حجم المنتج: ٤٢٠ × ٧٢ مم يتكيف مع سمك : 40-120 مم طريقة فتح القفل: مسح الوجه/بصمة الإصبع/كلمة المرور/المفتاح/مسح البطاقة/كلمة المرور المؤقتة/الفتح عن بعد/التطبيق / بصمة راحة اليد نوع الإنذار:إنذار مانع للانزلاق/إنذار انخفاض البطارية/إنذار تجريبي', 24000.00, 1, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FAjlFN1cVGzPicture1.jpg?alt=media&token=23813ab3-26e8-4e15-8556-82234a1087ed", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FqCKTCvEhE4C7(black).jpg?alt=media&token=dba1f92c-c644-4e20-a9bf-4286883dee2c", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FY2HAIqm9ZIC7%EF%BC%88Coffee%20Gold%EF%BC%89.jpg?alt=media&token=ac9906b4-de34-4dc1-882c-27a334892a94"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30088, 'Smart Curtain Mini Switch RF433 with Remote', 'Smart Curtain Mini Switch RF433 with Remote', '• وفر المال والجهد - مع مجموعة مفاتيح الراديو المُعدّلة، يمكنك بسهولة وسرعة التحكم اللاسلكي في محرك الستائر الدوارة، سواءً كان ذلك للتركيب أو للتركيب الجديد. مع هذه المجموعة، يُمكنك ترقية الستائر الدوارة والمظلات لتشغيلها بشكل مريح عن طريق جهاز التحكم عن بُعد. • سهل التركيب - يتميز المفتاح اللاسلكي بسهولة الاستخدام وسهولة تعلمه. تم تعليم جهاز الاستقبال جهاز التحكم عن بُعد من المصنع. يتناسب جهاز الاستقبال (بأبعاد 5 × 4.5 سم) مع أي صندوق قياسي مُثبّت على الحائط. يتم توصيل جهاز الاستقبال بالطاقة والمفتاح والمحرك، ثم إيقاف تشغيله بجهاز التحكم عن بُعد. • سهل الاستخدام - بفضل جهاز التحكم عن بُعد، يُمكنك التحكم في الستائر التي يصعب الوصول إليها لاسلكيًا من الأريكة | مساعدة مريحة للمرضى وذوي الإعاقات الجسدية | يمكنك وضع جهاز التحكم عن بُعد في أي مكان يناسبك أو تخزينه على حامل الحائط المُرفق. • أضف مفاتيح حائط بدون أسلاك - سهولة التركيب؛ توصيل الطاقة والإضاءة بأسلاك، لا حاجة لأسلاك مدمجة؛ أفضل طريقة لإصلاح التركيبات الخاطئة أو استبدال المفاتيح التي يصعب الوصول إليها. • نطاق الاستخدام: ستحصل على جهاز استقبال لاسلكي واحد، وجهاز تحكم عن بُعد واحد. مجموعة مفاتيح ستائر دوارة لاسلكية قابلة للتعديل، تُسهّل التبديل والتحكم في المحركات الكهربائية للستائر الدوارة، والستائر، والمظلات، والحماية من الشمس.', 1850.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F2KvHRhDvooc5fb387c-cef4-4cb9-b4fc-fade7337e541.jpeg?alt=media&token=d3daed43-0513-442d-9c91-98144fd4cda9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FCfLWbRWel7b6d47dba-e301-4edf-91d4-7708ff8f108f.jpeg?alt=media&token=e8b6e79b-f99f-4637-9438-817988ace2aa", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FciajyYChuhf2b209b9-45b6-4cfe-a99a-9161d0f10404.jpeg?alt=media&token=2699a753-61e8-4588-9fcc-2fa6518caace", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F11u09pmHqo71TR91mCqJL._SX522_.jpg?alt=media&token=c2aed5dd-1f4c-4473-ba87-871d5e8881fd"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30087, 'SMART DOOR LOCK Kadonio Remote Video Intercom Tuya Camera Automatic Unlock Smart WiFi Security 3D Face Recognition Door Lock', 'SMART DOOR LOCK Kadonio Remote Video Intercom Tuya Camera Automatic Unlock Smart WiFi Security 3D Face Recognition Door Lock', 'استمتع بالراحة والأمان مع قفلنا الذكي المتطور المزود بتقنية التعرف على الوجه. يوفر هذا القفل المتطور نظام فتح متعدد الاستخدامات، يجمع بين "التعرف على الوجه، ومسح بصمات الأصابع، وإدخال كلمة المرور، وتمرير البطاقة، والوصول بالمفتاح التقليدي، وتقنية NFC، والتحكم بالهاتف الذكي عبر تطبيق Tuya". مع سعة تسجيل تصل إلى 350 (ملامح الوجه، وبصمات الأصابع، وبطاقات IC، وكلمة المرور)، يوفر هذا المنتج مرونة وسهولة وصول لا مثيل لها. يفتح القفل تلقائيًا عند اكتشافه، ويغلق نفسه تلقائيًا بعد إغلاق الباب. يعمل ببطارية ليثيوم طويلة الأمد بسعة 4200 مللي أمبير/ساعة، مما يضمن عمرًا افتراضيًا يزيد عن ستة أشهر. يمكن إعادة شحنه بسهولة عبر منفذ Micro-USB. أبعاد المنتج 440*75*76 مم.', 11700.00, 1, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FxY8hbOGuy0H7ecf9fa512cd4cfa842decdf8fcbe5bbk%20(1).avif?alt=media&token=e262c5f8-187c-43cf-9ddc-c2c5cfd92ce7", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FAIuHbQljhyA012b9a9da6d24d72ad766fb94f59e314g.jpg_720x720q50.avif?alt=media&token=5f60fc3b-ace8-4bf4-bac6-312ed544cb6d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fy9eb8ucnXTH002fc2c04df149a7be27349273063d3ev.jpg_720x720q50.avif?alt=media&token=3d3d7cc0-5572-4082-91cc-4ff7fe641c9d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FAqsNgFdoRBH6ee854aa54484e61bc013b6bba00ae74B.jpg_720x720q50.avif?alt=media&token=4f5dee4c-3896-4617-9a57-9bb0bd994c23", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FpVAJC7SNRlH72d6b713f0454683ae5669936fe1abc2M.jpg_720x720q50.avif?alt=media&token=2d579332-683b-4fdb-b816-2df95320c472", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FOrIanqJ9a4H7487b6167690479cae6a37dd38d24aacr.jpg_720x720q50.avif?alt=media&token=7d2a0c38-29fe-40c5-84be-53c074ba1f0f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FCE7XLzprr0Hf8084c9e8d2b45df9dfd9f6784e923ffu.jpg_720x720q50.avif?alt=media&token=193a2fd9-8274-4e71-8252-4f4653578a07", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F2ykDuSmsL7Hfb9232c5330f48429f19634c6785fd729.avif?alt=media&token=cf7d4d41-5b7f-45e3-9389-b10c6dc48be5"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30085, 'TUYA light switch with Socket , white', 'TUYA light switch with Socket , white', '• قابس كهربائي مركب مع مفتاح. يتميز هذا المقبس المنزلي بقوة قصوى تبلغ 250 فولت/16 أمبير تيار متردد، ويدعم معظم الأجهزة المنزلية، وهو حاصل على شهادة CE/RoHS. • مفتاح أحادي الاتجاه - يمكنك تشغيل أو إطفاء إضاءة داخلية واحدة باستخدام هذا المفتاح الكهربائي أحادي الاتجاه. لا يدعم واي فاي، ولا يتوافق مع أليكسا، ولا يحتوي على باهتة إضاءة، ولا يمكن استخدامه كمفتاح ثنائي الاتجاه. • حالة LED: كل زر من أزرار مفتاح اللمس مزود بإضاءة خلفية. تشير الإضاءة الخلفية الزرقاء بوضوح إلى أن المصباح قيد التشغيل/الإيقاف، ويسهل العثور عليه في الظلام، ولكنه لا يؤثر على النوم. • تصميم آمن: مقبس Schuko غائر مع نقاط تلامس أرضية وحماية إلكترونية من ماس كهربائي. زجاج مقاوم للصدمات. يجب عدم إشعال غطاء الحماية من الحريق وغطاء الوحدة أبدًا. • مظهر أنيق: لوحة اللمس الزجاجية الأنيقة تناسب أي غرفة تمامًا. يمكن تركيب المقبس المزود بمفتاح مسطح رأسيًا وأفقيًا على الحائط.', 2000.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FglUv3fkCiY41rq5fNE55L._SL1200_.jpg?alt=media&token=849bc81c-1be1-49d5-8e84-78ae9749ffda", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F6MN8dNCr1X41gZ0mdWYZL._SL1200_.jpg?alt=media&token=5546b6a5-8364-4f35-8f95-cd6ac01394a4", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FJOPpuLWJbZ51WEV7561EL._SL1200_.jpg?alt=media&token=75d03341-9049-485a-b1f2-2faf280a3c97", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FX4S4luErYN61GPVFYiJgL._SL1200_.jpg?alt=media&token=a78ac0ab-27cb-4f9a-84ac-e624b004c51d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FT4iPqnMcej71eE2aBqu5L._SL1200_.jpg?alt=media&token=f6eb9cf8-03af-4dec-b155-9e280d3ef0bd", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FdueJKpDtZx61NZJOdMsKL._SL1200_.jpg?alt=media&token=0d196547-c7d4-40c4-9f92-086c7f39d3ce", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F9EvhaToW0V61ucH3h3pBL._SL1500_.jpg?alt=media&token=6380b1e6-c113-4a71-bf3e-70de7c2f143e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FKsm7aIguQ471C%2B8U0jCxL._SL1200_.jpg?alt=media&token=71b4fbf4-caa2-43fb-b597-585513020865"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30086, 'TUYA light switch with Socket , grey', 'TUYA light switch with Socket , grey', '• قابس كهربائي مركب مع مفتاح. يتميز هذا المقبس المنزلي بقوة قصوى تبلغ 250 فولت/16 أمبير تيار متردد، ويدعم معظم الأجهزة المنزلية، وهو حاصل على شهادة CE/RoHS. • مفتاح أحادي الاتجاه - يمكنك تشغيل أو إطفاء إضاءة داخلية واحدة باستخدام هذا المفتاح الكهربائي أحادي الاتجاه. لا يدعم واي فاي، ولا يتوافق مع أليكسا، ولا يحتوي على باهتة إضاءة، ولا يمكن استخدامه كمفتاح ثنائي الاتجاه. • حالة LED: كل زر من أزرار مفتاح اللمس مزود بإضاءة خلفية. تشير الإضاءة الخلفية الزرقاء بوضوح إلى أن المصباح قيد التشغيل/الإيقاف، ويسهل العثور عليه في الظلام، ولكنه لا يؤثر على النوم. • تصميم آمن: مقبس Schuko غائر مع نقاط تلامس أرضية وحماية إلكترونية من ماس كهربائي. زجاج مقاوم للصدمات. يجب عدم إشعال غطاء الحماية من الحريق وغطاء الوحدة أبدًا. • مظهر أنيق: لوحة اللمس الزجاجية الأنيقة تناسب أي غرفة تمامًا. يمكن تركيب المقبس المزود بمفتاح مسطح رأسيًا وأفقيًا على الحائط.', 2000.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FiBv9v23cGs51JUMyoQNEL._SL1500_.jpg?alt=media&token=62cfffb5-0fde-41c4-ba6f-17ffe3661744", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FmamSNPf19I51tpGuBlvsL._SL1500_.jpg?alt=media&token=4b9a4135-72e7-42b3-b28f-97e09a7d2d4a", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fs7kscD1rmn61a3kRdQ6KL._SL1500_.jpg?alt=media&token=cd659e5a-df79-4036-aa59-6a9ceb5bc1de", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F5b88vhOXvX71wfjy9lBsL._SL1500_.jpg?alt=media&token=44173e54-8267-4a4f-9462-2be96e97cd4b", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F4YaPNFRDWB7136eaFOy5L._SL1500_.jpg?alt=media&token=ce08b512-606c-430e-b4b6-2545eb0d716f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FFdT3uEV1SV61-g58QG3nL._SL1500_.jpg?alt=media&token=9a64863d-dd82-4395-ba03-3943577be9de"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30084, 'SWITCH TUYA 2GANG +BLUG ZIGBEE', NULL, '• \\\\\\\\\\\\توافق متعدد الاستخدامات: متوافق مع Zigbee Hub 3.0، مما يوفر تحكمًا ذكيًا ولاسلكيًا. • كفاءة الطاقة: حماية من زيادة التيار الكهربائي 1680 جول ووظيفة جدولة لتوفير الطاقة. • مقبس ذكي للتحكم الذكي: يتكامل مع Smart Life/Tuya وAlexa وGoogle Home للتحكم عن بُعد والأوامر الصوتية. • شهادة السلامة: حاصل على شهادة CE/ROHS/FCC، مما يضمن السلامة والموثوقية. • تصميم أنيق: تصميم أنيق من الزجاج، مثالي لمنزل ذكي دون شغل حيز كبير من المساحة.', 2225.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fr1WhB7JdcsH4d4fc7dcd9e64d338024237f695731133.avif?alt=media&token=5c09d0e0-a8dc-439d-b036-defceeace58f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FhhW5hSdHobHef68f142694a4f51a778c097c42a16e0M.avif?alt=media&token=47e7caf8-da2c-4b34-8979-3993b6a33fd6", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F75sVoHV45Is-l1600%20(2).webp?alt=media&token=27908d41-47ac-46aa-a6b7-3ef83ea7f546", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FcFgPT160kRs-l1600%20(1).webp?alt=media&token=97fbc987-f37d-4548-8121-d4d38e070c04", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F5cj129nvVWHd32ebd4236f0478fb26448ed2f5dd6b7D.avif?alt=media&token=3ef9dbe6-3719-4c66-8ae8-bc965138b4c3", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Frt9GpXO7INH7b87984854f84e8bb5b71500bc01fd24N.avif?alt=media&token=97c83e9e-f652-44bd-b3ad-5dd19569f838", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FlNZdzl7zO2Hc362f48b67144e1f9b9be81fa7e5c644v.avif?alt=media&token=184dfae7-2727-4364-84ef-9fa275442391", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FzRWVRQsxUlHd7e4c749125e457ab62703e77b97c682g.avif?alt=media&token=ca800afd-b9a1-443b-a110-96bcd7859e20"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30083, 'TUYA Plug Socket WIFI', NULL, '• تحكم عن بُعد في المقبس عبر تطبيق الهاتف المحمول • متوافق مع أجهزة الأوامر الصوتية مثل Amazon Alexa أو Google Home • 16 أمبير لزيادة حمل الجهاز للأجهزة الكهربائية • استخداماته متعددة، ويمكن استخدامه مع أكثر من جهاز كهربائي، مثل ماكينة القهوة، ومكواة الملابس، والعديد من الأجهزة الكهربائية الأخرى • يمكنك ضبط مؤقت لإيقاف تشغيل الجهاز تلقائيًا في حال نسيان توصيله بالكهرباء', 2000.00, 30006, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FESaS2G0FtUP2.jpg?alt=media&token=7588a0c5-cce6-4aa5-a167-ffb6144847d9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fz1M6UrjMejP4.jpg?alt=media&token=5674fefe-9c12-4ae6-837a-d0800a8bc95e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FZ91eI7hKbcP5.jpg?alt=media&token=5d1e1f6a-5c96-40d7-8832-56018be2a1fc"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30082, 'Tuya Water Valve Zigbee Tuya Smart Water Valve Shutoff, Automatic Ball Valve Watering Timer, Sprinkler Controller, Compatible with Alexa and Google Assistant and App iOS/Android, Wireless Remote Control', NULL, '• الصمام الذكي: صمام زيجبي ميكانيكي، يتطلب بوابة زيجبي للاستخدام. على سبيل المثال، بوابة تويا تدعم زيجبي 3.0. من خلال البوابة، يمكنك الاتصال بسهولة واستخدام ميزاتنا الذكية. يتميز جهاز التحكم بمفتاح الصمام الذكي لأتمتة المنزل بتصميم فريد مع استهلاك منخفض للطاقة وحماية فائقة. يُستخدم مفتاح صمام المياه أليكسا على نطاق واسع في البيئات، والحدائق، والمطابخ، والأراضي الزراعية، وحمامات السباحة، وغيرها. • التحكم الصوتي: يعمل جهاز التحكم بمفتاح صمام المياه زيجبي مع أليكسا وجوجل هوم، ما عليك سوى توصيلهما لنطق الأمر مباشرةً، وسيفتح/يغلق جهاز التحكم، مما يوفر عليك الجهد والوقت. • التحكم عن بُعد: عند الاتصال بالجهاز عبر بوابة زيجبي، يمكنك التحكم بسهولة في تشغيل/إيقاف صمام المياه من خلال التطبيق. كما يمكنك التحقق من حالة جهازك من خلال التطبيق. نستخدم هذا التطبيق في تطبيقات جينفو الذكية / الحياة الذكية / تويا. وظيفة التوقيت: بعد توصيل وحدة تحكم صمام المياه بالإنترنت، يمكنك ضبط وقت الفتح والإغلاق حسب رغبتك، مما يوفر استهلاك المياه، ولن تنساه، وهو أمر مريح للغاية. مثال: في الساعة 8 صباحًا، يتم تشغيل نظام الري الذكي للحديقة. الخدمة الفنية: إذا كانت لديك أي أسئلة حول صمام ZigBee، فيُرجى الاتصال بنا في الوقت المناسب، وسنرد عليك في غضون 24 ساعة. يتطلب التركيب القليل من الصبر والوقت، ويمكن أن تساعدك البراغي ومشابك الخرطوم المصنوعة من الفولاذ المقاوم للصدأ على تثبيت الصمام بشكل أفضل. يُرجى قراءة دليل التعليمات بعناية قبل التركيب.', 3000.00, 30009, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FfsteogNI2e61aVAPiL2zL._AC_SL1500_.jpg?alt=media&token=3e69d839-661a-42bd-9a9b-1c80cfaa19f7", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fqblp9ZZn2651IEWXdunrL._AC_SX679_.jpg?alt=media&token=c603b23a-b513-4546-90a3-fb92eaafb7eb", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FYUtx1sboCi41Ir-BtqskL._AC_.jpg?alt=media&token=b1cc8592-1d1f-411a-bccc-18cdf300a8d6", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fn4DeNJKFi961fxTPsSlVL._AC_SL1500_.jpg?alt=media&token=01b7b7bd-7fa5-4444-b99a-618f4538d4e0", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FJ9qwRw7rte61Gs4Xvg5-L._AC_SL1500_.jpg?alt=media&token=c125114b-f53f-4dd8-8cd3-064d84833960", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FSP4L8ODKDv71aPrS43D4L._AC_SL1500_.jpg?alt=media&token=def67b2a-eeec-44d1-95c6-36bfc924333d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fo5A7tpngCM614htWHu56L._AC_SL1500_.jpg?alt=media&token=673b2222-47eb-4083-8cc9-fd89072f7fbd", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FqeDQyR2jG5617Y1Jw7zEL._AC_SL1500_.jpg?alt=media&token=b9c28a8e-37ad-402c-bfd7-e732ac2695a3", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fvk3BR87COL819ceDg%2BmPL._AC_SL1500_.jpg?alt=media&token=ed11d15a-5409-426a-a3e6-ecac9acc39db"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30081, 'Smart Meter Wifi Switch, 1P+N AC90-240V 1-50A', NULL, '• هذا المنتج مفتاح واي فاي ذكي مزود بحماية من التيار الزائد، والجهد الزائد، والجهد المنخفض، والطاقة الزائدة، ودرجة حرارة وحدة المعالجة المركزية، ولكنه لا يوفر حماية من قصر الدائرة. يُنصح باستخدامه مع قاطع دائرة. يتوافق مع معيار IEC 60947. • حالات التيار المطبق: تيار متردد -1، يُستخدم في دوائر التحكم في السخانات، والمصابيح المتوهجة، والأفران، وغيرها من الأحمال المقاومة بحتة؛ أقصى سعة توصيل: جانب الطاقة: 10 مم²؛ جانب الحمل: 10 مم²؛ النوع: مرحل مزود بقفل، قادر على حمل تيار عالي؛ وصف الأقطاب: 1P+N، لا يمكن فصل القطب N. • مراقبة الطاقة في الوقت الفعلي (استيراد تيار متردد إيجابي) وإدارتها: (1) تحليل استهلاك الكهرباء، والتيار، والجهد، والطاقة في الوقت الفعلي للأجهزة المتصلة، وتسجيل تاريخ استهلاك الطاقة (بالساعة، واليوم، والشهر، والسنة). كما يمكن تصدير بيانات استهلاك الطاقة عبر البريد الإلكتروني. (2) مسح بيانات الكهرباء. (3) توجد وظائف لعرض الكهرباء المتبقية الحالية، والتبديل المدفوع مسبقًا، ومسح الكهرباء المتبقية، مما يسهل إدارة الكهرباء الشاملة. التحكم المحلي: (1) حتى في حالة عدم وجود شبكة واي فاي، يمكنك ضبط الإعدادات والوظائف من خلال الأزرار الثلاثة الموجودة على مفتاح واي فاي الذكي. (2) يمكن تعيين كلمة مرور لمنع الوصول غير المصرح به والتعديل. • وظائف إعادة الإغلاق المتعددة: تتوفر وظائف إعادة الإغلاق عند زيادة التيار، وزيادة الطاقة، وزيادة الجهد وانخفاض الجهد. يرجى ملاحظة أنه بعد الحماية من زيادة التيار/زيادة الطاقة، سيحاول الجهاز إعادة الإغلاق ثلاث مرات. إذا استمر التيار/زيادة الطاقة، فلن تتم إعادة الإغلاق مرة أخرى. بعد الحماية من زيادة الجهد وانخفاض الجهد، سيعيد الجهاز الإغلاق تلقائيًا. حد الإغلاق: حد الجهد الزائد -15 فولت، حد الجهد المنخفض +15 فولت. • شاشة العرض: مفتاح ذكي مزود بشاشة LCD ملونة بإضاءة خلفية، بيانات واضحة وسهلة القراءة. قابل للتعديل من 1 إلى 5 مستويات سطوع واتجاه. • عناصر تحكم متعددة عبر واي فاي: (1) التحكم عن بُعد عبر التطبيق: يمكنك التحكم في الأجهزة المنزلية عبر تطبيق "Smart Life" أو "Tuya". لا توجد قيود على المسافة والوقت. (2) التحكم الصوتي: مفتاح واي فاي متوافق مع أمازون أليكسا ومساعد جوجل. يمكنك التحكم في أجهزتك المنزلية باستخدام مفتاح الأوامر الصوت', 6000.00, 30009, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FpGPos7IdEvt.jpg?alt=media&token=f0976ba6-cc54-443b-95e4-dda9dfc5e3cb", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FV5tryzeKwU1.jpg?alt=media&token=6ff9e469-9531-451c-b2a8-c948ff8d1343", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fv5bPlMS1aT61E3aXVA0WL._SL1500_.jpg?alt=media&token=2f5dcfb5-f63b-4cca-98e1-d83d2c175fe4", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FHqcMfT2g0l61TRotJ%2Bc5L._SX522_.jpg?alt=media&token=f3b8c7e6-e28c-46e6-a848-d4a6d435038a", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F1lldAJSjmD71jurrm2RQL._SX522_.jpg?alt=media&token=617004bf-a1e1-4788-9e04-266bd2615f11", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FnprjJHpM0g71nzs-nNwqL._SL1500_.jpg?alt=media&token=412da8df-fc95-487c-993b-14a73cab23ec", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FQtNeiFRbG271p5I187RLL._SX522_.jpg?alt=media&token=c43df2fb-3bee-4c5f-b8e3-dbc9bc2f323c"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30080, 'IR BLACK&WHITE Smart WIFI IR Universal controller for all IR devices', NULL, '• تحكم شامل: يُمكن لجهاز التحكم عن بُعد الذكي هذا التحكم في أجهزة الأشعة تحت الحمراء المختلفة، مما يوفر حلاً عمليًا لإدارة أجهزة متعددة بجهاز واحد. • تحكم بعيد المدى: يتميز بمدى واي فاي يصل إلى 45 مترًا ومسافة الأشعة تحت الحمراء 7 أمتار، مما يسمح بالتحكم السلس عن بُعد. • متوافق مع التحكم الصوتي: تم دمج هذا المنتج مع تطبيق Tuya Smart Life، مما يتيح التحكم الصوتي من خلال المساعدين الصوتيين المشهورين، مما يُسهّل التحكم في الأجهزة بأوامر صوتية فقط. • قابل للتخصيص: يدعم منتجنا تخصيص الشعار، مما يسمح للشركات بتخصيص جهاز التحكم عن بُعد بشعار علامتها التجارية، مما يعزز التعرف على العلامة التجارية. • أداء موثوق: مع مستوى حماية IP53 ، يضمن هذا المنتج أداءً موثوقًا ومتانة، مما يوفر راحة البال للمستخدمين.', 1250.00, 30003, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Ft0ilZFVxDsH2da8d26b66b8435b8ba5ff38c82ed5e9S.jpg_720x720q50.avif?alt=media&token=9414f067-a3ad-4c2e-8f0c-ed3b3e9fc4b9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FE25eKNjylmH5172c32783b8436da4cbcff1e0339a07J.jpg_720x720q50.avif?alt=media&token=22c42bae-30d3-49ca-b747-b82faafe35c5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FfnL1WrE5MbH47253c6dc3754c6d910a24923c63d99bR.jpg_720x720q50.avif?alt=media&token=8b189708-77a1-4bb2-8cbc-6fa3f5d3b5f0", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FfYeqFzUIcBHd682f7c305c8466096c8d18c7ddc8bbdk.jpg_720x720q50.avif?alt=media&token=e75d3b85-1169-4d9d-b999-5dd2979bfa6b", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FY4gbcmGgXVtuya-smart-wifi-mini-ir-controller.jpg?alt=media&token=d23e3eac-e031-47db-a1b9-7cb9b983a90e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F7Vpf8MsH8Wtuya-smart-wifi-mini-ir-controller%20(1).jpg?alt=media&token=b55176bd-8b63-499d-b2d0-22ea912b4b18"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30079, 'Tuya WiFi IR Black Remote Control for Air Conditioner TV, Smart Home Infrared Universal Remote Controller For Alexa,Google Home', 'Tuya WiFi IR Black Remote Control for Air Conditioner TV, Smart Home Infrared Universal Remote Controller For Alexa,Google Home', '• جهاز التحكم عن بُعد هذا هو جهاز تحكم عن بُعد ذكي يعمل بتقنية واي فاي، ويدعم التحكم الصوتي من جوجل هوم/نيست وأليكسا. مناسب للتلفزيون/جهاز الاستقبال/جهاز الاستقبال الرقمي/مكيف الهواء/المروحة/الستائر الكهربائية بالأشعة تحت الحمراء، إلخ. • الميزات: • تحكم شامل: يُشغّل جهاز التحكم عن بُعد الشامل بالأشعة تحت الحمراء مكيفات الهواء، والتلفزيون، وجهاز الاستقبال الرقمي، والمراوح، والستائر الكهربائية بالأشعة تحت الحمراء، إلخ. • التحكم عبر التطبيقات: اجعل الأجهزة المنزلية ذكية، ويمكنك التحكم في الأجهزة المنزلية التي تعمل بالأشعة تحت الحمراء من خلال تطبيق تويا سمارت أو تطبيق سمارت لايف في أي وقت وفي أي مكان. • التحكم الصوتي بدون استخدام اليدين: غيّر درجة حرارة مكيف الهواء، وشغّل المراوح، وغيّر قناة التلفزيون، وشغّل أقراص DVD، وافتح جهاز الاستقبال الرقمي، إلخ، باستخدام التحكم الصوتي بدون استخدام اليدين من جوجل هوم/نيست وأليكسا. • وظيفة التعلم: إذا لم تتمكن من العثور على جهاز الأشعة تحت الحمراء في تطبيق سمارت لايف، يمكنك استخدام وظيفة التعلم "اصنعها بنفسك" القابلة للبرمجة لنسخ نفس الوظيفة من جهاز التحكم عن بُعد الأصلي. • التوافق: يدعم هذا الإصدار فقط إشارات بمعدل ترميز 38 كيلوبت في الثانية واتصال واي فاي 2.4 جيجاهرتز. يُنصح باستخدام جهاز تحكم ذكي بالأشعة تحت الحمراء في الغرفة، لأن الأشعة تحت الحمراء لا يمكنها اختراق الجدران. • المواصفات: • نوع المنتج: جهاز تحكم عن بُعد عالمي • المادة: ABS • المدخل: تيار مستمر ٥ فولت/١ أمبير • تردد الأشعة تحت الحمراء: ٣٨ كيلو أوم • معيار الاتصال اللاسلكي: ٢.٤ غرام هرتز • حجم المنتج: ٦.٥ × ٢.٥ سم/٢.٥٦ × ٠.٩٨ بوصة • وزن المنتج: ٢٣.٧ غرام/٠.٨٤ أونصة • حجم العبوة: ٧ × ٧ × ٥ سم/٢.٧٦ × ٢.٧٦ × ١.٩٧ بوصة • وزن العبوة: ٥٩.٦ غرام/٢.١٠ أونصة • قائمة التعبئة: • ١* جهاز تحكم عن بُعد عالمي • ١* كابل USB • ١* دليل المستخدم', 1350.00, 30003, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FVHZz9di3TnTuya-Wifi-Smart-IR-Remote-Controller-3_grande.webp?alt=media&token=56111628-f208-4edd-b95c-cce310abd5f2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F27CNlVvdffTuya-Wifi-Smart-IR-Remote-Controller-5-1_grande.webp?alt=media&token=6dacf959-3446-4283-a213-e5f5acbfe0fc", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Feb4JaTZx9PTuya-Wifi-Smart-IR-Remote-Controller-7_grande.webp?alt=media&token=dfd56db4-75a8-4059-af93-d73ad704c848", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F8FlgMLz60JTuya-Wifi-Smart-IR-Remote-Controller-9_grande.webp?alt=media&token=3c4e918d-790f-4e6f-8c49-5901a9240aab", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fh5IVXnep2B02be61934adc13d31ee3a6c89201dcfe30dd230a_1024_1024.jpeg?alt=media&token=7a1bd674-a4d7-4859-98e7-f863cefe424a", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FGDC4Kc1VRc2dbf43fc4c9e540ea9da666c4bbb059d191d894c_1024_1024.jpeg?alt=media&token=d3a80c50-b616-4f29-95a8-02883b3b59f8", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FKllWkXv24y2de023b51703515d3d359df94b72305b2978ace4_1024_1024.jpeg?alt=media&token=8852cc0f-b248-4ee1-aafb-d481eb6eb662", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FU99Jcehu633c38a36eaee869e067e0c73182ad1e308f5e0e8f_1024_1024.jpeg?alt=media&token=0e051e8d-6b27-4ebe-a60c-9c44effbfaa3", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FJ7vqL02bA2927429f2d1ce864c9072de3bd91983fb21401fc1_1024_1024.jpeg?alt=media&token=0cf42688-85bb-4605-856c-5ef70fb02abc"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30078, 'Tuya WIFI Smart IR Remote Controller White Smart Home Infrared Universal Remote Control for Air', 'Tuya WIFI Smart IR Remote Controller White Smart Home Infrared Universal Remote Control for Air', '• جهاز التحكم عن بُعد هذا هو جهاز تحكم عن بُعد ذكي يعمل بتقنية واي فاي، ويدعم التحكم الصوتي من جوجل هوم/نيست وأليكسا. مناسب للتلفزيون/جهاز الاستقبال/جهاز الاستقبال الرقمي/مكيف الهواء/المروحة/الستائر الكهربائية بالأشعة تحت الحمراء، إلخ. • الميزات: • تحكم شامل: يُشغّل جهاز التحكم عن بُعد الشامل بالأشعة تحت الحمراء مكيفات الهواء، والتلفزيون، وجهاز الاستقبال الرقمي، والمراوح، والستائر الكهربائية بالأشعة تحت الحمراء، إلخ. • التحكم عبر التطبيقات: اجعل الأجهزة المنزلية ذكية، ويمكنك التحكم في الأجهزة المنزلية التي تعمل بالأشعة تحت الحمراء من خلال تطبيق تويا سمارت أو تطبيق سمارت لايف في أي وقت وفي أي مكان. • التحكم الصوتي بدون استخدام اليدين: غيّر درجة حرارة مكيف الهواء، وشغّل المراوح، وغيّر قناة التلفزيون، وشغّل أقراص DVD، وافتح جهاز الاستقبال الرقمي، إلخ، باستخدام التحكم الصوتي بدون استخدام اليدين من جوجل هوم/نيست وأليكسا. • وظيفة التعلم: إذا لم تتمكن من العثور على جهاز الأشعة تحت الحمراء في تطبيق سمارت لايف، يمكنك استخدام وظيفة التعلم "اصنعها بنفسك" القابلة للبرمجة لنسخ نفس الوظيفة من جهاز التحكم عن بُعد الأصلي. • التوافق: يدعم هذا الإصدار فقط إشارات بمعدل ترميز 38 كيلوبت في الثانية واتصال واي فاي 2.4 جيجاهرتز. يُنصح باستخدام جهاز تحكم ذكي بالأشعة تحت الحمراء في الغرفة، لأن الأشعة تحت الحمراء لا يمكنها اختراق الجدران. • المواصفات: • نوع المنتج: جهاز تحكم عن بُعد عالمي • المادة: ABS • المدخل: تيار مستمر ٥ فولت/١ أمبير • تردد الأشعة تحت الحمراء: ٣٨ كيلو أوم • معيار الاتصال اللاسلكي: ٢.٤ غرام هرتز • حجم المنتج: ٦.٥ × ٢.٥ سم/٢.٥٦ × ٠.٩٨ بوصة • وزن المنتج: ٢٣.٧ غرام/٠.٨٤ أونصة • حجم العبوة: ٧ × ٧ × ٥ سم/٢.٧٦ × ٢.٧٦ × ١.٩٧ بوصة • وزن العبوة: ٥٩.٦ غرام/٢.١٠ أونصة • قائمة التعبئة: • ١* جهاز تحكم عن بُعد عالمي • ١* كابل USB • ١* دليل المستخدم', 1350.00, 30003, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fo9mYs0HuNib19e3452cedf3d7332089780449866320dcad9c5_1024_1024.jpeg?alt=media&token=afc3f9ad-25dd-4ff0-9d49-98ddad6f8a1d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FaDDQrVSBvKa7fc65e3e1d1eab09262968f33c3d8f6f37d4d65_1024_1024.jpeg?alt=media&token=d494a350-297a-4be7-83bc-10f2ffca2ab7", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FDr3k0J1o4d39945449b1af3fae16ae29b4c7c26a400a4b026b_1024_1024.jpeg?alt=media&token=7dc40ca3-76ff-4946-a9dd-f367132c158a", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FLOtkuE4tiO17260f3b41d507d1b38978fd43a9e736ce2130db_1024_1024.jpeg?alt=media&token=d9f0759f-2aec-4da4-a2d2-057092c869d2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FrEOVlNcXvh185a44e039d985f3dddb240de142cb256fef092a_1024_1024.jpeg?alt=media&token=58c08a9c-6d05-4d83-ae21-284faa42f2ff", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FZVTvPS0noA22e5fccfb69a9b52d485b9ef1fe95605ed519217_1024_1024.jpeg?alt=media&token=d95aba4f-453b-4bb3-a88c-941b71607fc1", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FXiMH7XuyqQ7be928438a0a0ac89aa1cd145b98b51786db76e1_1024_1024.jpeg?alt=media&token=7b561d77-22c3-4d8a-a291-b1ca3a5b6140", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FvgKbjxudP56c57b49d45d2b77af2298b8337303ac1cc255cb2_1024_1024.jpeg?alt=media&token=8929c08d-4af8-4342-81fb-82dd01100af2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2