INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30077, 'TUYA Smart Water valve & Gas Valve WiFi', 'TUYA Smart Water valve & Gas Valve WiFi', 'صمام ذكي: وحدة التحكم الذكية لصمام الغاز مناسبة للتحكم الذكي والكهربائي واليدوي في صمام الكرة لأنابيب الغاز. بالإضافة إلى ذلك، يمكن استخدامها أيضًا كصمام مياه. • مشهد الربط الذكي: يمكن توصيل أجهزة إنذار غاز قابلة للاشتعال مختلفة. عند اكتشاف تسرب غاز، سيصدر إنذار الغاز القابل للاشتعال أمر إيقاف التشغيل في نفس وقت الإنذار، وستنفذ وحدة التحكم الذكية لصمام الغاز الأمر لإغلاق صمام الكرة لحماية سلامة المنزل. • التحكم الصوتي والتطبيق: يدعم التحكم الصوتي، ويمكنك التحكم في فتح وإغلاق الصمام من خلال أليكسا ومساعد جوجل. كما يدعم التحكم عن بُعد، حتى إذا لم تكن في المنزل، يمكنك استخدام هاتفك المحمول للتحكم عن بُعد بمفتاح واحد لإيقاف تشغيل صمام الغاز. • صمام: مناسب لأنابيب الغاز المنزلية، ومناسب أيضًا لمتطلبات تركيب التحكم التلقائي في صمام الغاز أو السائل الأخرى، لتلبية التحكم الذكي/اليدوي للصمام. (ينطبق على صمامات المقبض من نوع ä وصمامات الفراشة) • الأنابيب المناسبة: مناسب لأنابيب رباعية وسداسية النقاط (يجب أن تكون أنابيب رباعية النقاط مبطنة بحلقات مطاطية ومثبتة على العبوة).', 3500.00, 30009, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F5ICkWvxzYW51Lf9ihWxQL._SX679_.jpg?alt=media&token=974c4e34-286c-45a5-a589-7af58de48d37", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FYtGlLZYDyZ180.webp?alt=media&token=f33d524d-c89b-4002-8b32-0d40c5ded1b2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FXLf3kr7NNS180%20(1).webp?alt=media&token=cacdef33-440a-46c2-9b1a-2aea0bc803bf", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F6gaG7UjujB180%20(2).webp?alt=media&token=c45e2482-772f-4289-be10-9723db4f4f42", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FWRncUL3HOb180%20(3).webp?alt=media&token=0830d4f4-50d7-40e0-8c0d-a9aedb187903", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fh4KidjDfhX180%20(4).webp?alt=media&token=8691aaf2-4f39-4b25-8bf6-4df522cbbd13", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fyl67GyMu8K180%20(5).webp?alt=media&token=20f28701-1f12-486c-88ac-a42847fd4fca", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FrvCE1qeyFs180%20(6).webp?alt=media&token=b4633c54-cca6-45fc-8998-12fa83f160c5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FSJT5j0bbnO180%20(7).webp?alt=media&token=d64c0fb2-8e04-40e4-a6db-adf35e37713c"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30076, 'Smart Radiator Thermostat ZIGBEE', 'Smart Radiator Thermostat ZIGBEE', 'تحكم ذكي: صمام المبرد الحراري هو منظم حرارة ذكي، يمكنك التحكم به عبر هاتفك المحمول قبل العودة إلى المنزل. • * قابل للتكوين أسبوعيًا: يدعم صمام التحكم في درجة الحرارة إعدادات مختلفة لدرجة الحرارة في 6 أوضاع زمنية يوميًا. • يوجد مستشعر أرضي داخلي، يمكنه استشعار درجة الحرارة المحيطة ودرجة حرارة الأرضية بدقة. • وظيفة فتح النافذة: عند فتح النافذة وانخفاض درجة حرارة الغرفة بأكثر من 6 درجات خلال 4 دقائق، ستعرض الشاشة رمز التشغيل، وسيتم إغلاق صمام منظم الحرارة الذكي. • إذا ارتفعت درجة حرارة الغرفة بمقدار 3 درجات، يمكن إلغاء تنشيط هذه الوظيفة تلقائيًا بعد 48 دقيقة.', 4100.00, 30009, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FARJJo070XZH84e2de14e4324ff0abb8bcaa616142edj.jpg_720x720q50.avif?alt=media&token=40e13dca-d00f-4261-9294-b92cdd471e9a", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FvSIYrAVbK7H0c4b2c72a5964485ae46ec1c3155c684q.jpg_720x720q50.avif?alt=media&token=b081588e-cbf5-4255-a8c3-891d3de22119", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FEm4kVgmAbsH0d7e09f98d5644e0aa9d1fc9d7cdf2483.jpg_720x720q50.avif?alt=media&token=0a6ac9af-47b2-4724-a50d-a84364cc9772", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FVaCEHZhM1CH3b727483e1f44a89a2442108c1594b948.jpg_720x720q50.avif?alt=media&token=1319905e-69aa-4f77-8232-66ca107d4945", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F8tiLlQlxRHH6eb054ded31d4fea96acf6219901e262O.jpg_720x720q50.avif?alt=media&token=78bf1022-20e3-406d-81fc-8c07d86f2cd5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fe4ZndBMiAFHd589760365b44a5782e72b2090c835adi.jpg_720x720q50.avif?alt=media&token=eb6916ba-2ddc-437c-98a0-5ebc1fb83fd9"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30073, 'BT- BLE smart gateway model tybl1', 'BT- BLE smart gateway model tybl1', '• تكامل متعدد الشبكات: حرية التبديل كنقطة اتصال واحدة وطريقة اتصال شبكية تجمع بين واي فاي وبلوتوث، ويمكن التحكم في القناة عن بُعد عبر واي فاي وبلوتوث محلي. حتى في حالة عدم وجود شبكة، يمكن معالجتها بشكل طبيعي للتحكم الذكي. • التحكم عن بُعد عبر التطبيق: بوابة بلوتوث ذكية ضرورية في نظام تويا للمنزل الذكي للتحكم في جهازك عن بُعد من أي مكان في العالم، حتى لو لم تكن في المنزل. لا حدود للمكان أو المسافة، سهل التحكم من خلال التطبيق. • التحكم الصوتي: يتوافق موزع بلوتوث مع أجهزة جوجل الذكية. يمكنك إصدار أوامر إلى جوجل هوم للتحكم في الجهاز عن طريق إصدار صوت لإعداد نظام مخصص يناسب احتياجاتك المختلفة. • مقاومة للتداخل: يستخدم موزع بلوتوث تشفيرًا متقدمًا في هذا المجال لنقل المعلومات عبر محطات واي فاي وبلوتوث لضمان أمان اتصالات الشبكة ومنع التطفل الخبيث. قدرة فائقة على اختراق الجدران، وقوة تداخل عالية، بالإضافة إلى خصائص تسخين منخفضة واستهلاك منخفض للطاقة. • سهولة الاستخدام ومشاركة الأجهزة: يتميز موزع البوابة الذكي بتصميم انسيابي، صغير الحجم، ويمكن وضعه في أماكن مختلفة، ويمكن توصيل ما يصل إلى 100 جهاز به، ويدعم مشاركة الأجهزة مع أفراد العائلة للتحكم المشترك. يمكن لعدة هواتف التحكم في الجهاز نفسه دون الحاجة إلى إصلاح، ومشاركة الأجهزة الموجودة مباشرةً.', 4900.00, 30003, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F3KFOxjqiSi1.webp?alt=media&token=62e036c9-e5a2-4d17-a495-08a214833828", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FEl1fxGoYj91597215358ef47e2fb96b.webp?alt=media&token=239e6d5d-c634-448c-91d0-342b0f231368", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F5Yn6b3qMC4159721536867b3e1d758a.webp?alt=media&token=768eff1c-ab9d-4000-880b-4b88ab0b7f96", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FUKqYdkI3fV4.webp?alt=media&token=a4345b00-4236-440b-b266-3df13f168e48", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fyq7ojwhZhV5.webp?alt=media&token=c180cb7b-335c-411d-92ec-e3b397955162"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30075, 'TUYA smart battery doorbell camera', NULL, 'تصنيف IP65 لمقاومة الماء: تتميز كاميرا جرس الباب هذه بتصنيف IP65 لمقاومة الماء، وهي مصممة للاستخدام الخارجي، ويمكن استخدامها في البيئات الممطرة والقاسية مع مقاومة ممتازة للغبار والماء، حتى في الأحوال الجوية السيئة لضمان سلامة منزلك. إعداد ذكي: يمكن إعداد كاميرا جرس الباب هذه بأحداث ذكية، أو ضبط توقيتات الجدول الزمني، أو ضبط ظروف التشغيل الآلي مثل كشف الحركة بالأشعة تحت الحمراء أو كشف العبث لتشغيل الإنذارات والتسجيل المباشر. خصص نظام أمان منزلك وفقًا للجدول الزمني. وظيفة تسجيل الأحداث: تتميز كاميرا جرس الباب هذه بوظيفة تسجيل الأحداث مع مساحة تخزين شهرية في التطبيق أو بطاقة تخزين مدمجة (غير متضمنة) لحفظ ومشاهدة سجل مراقبة الأحداث. كاميرا مدمجة بزاوية عريضة HD1080P: يمكن لكاميرا جرس الباب هذه التبديل تلقائيًا بين وضعي النهار والليل، مع كاميرا مدمجة بزاوية عريضة HD1080P بزاوية رؤية واسعة ورؤية ليلية استقرائية، مما يوفر صورة واضحة تتيح لك مراقبة الوضع خارج منزلك بشكل أفضل ليلاً. بطارية قابلة لإعادة الشحن: تستغرق البطارية القابلة لإعادة الشحن من 6 إلى 8 ساعات فقط لشحن كاميرا جرس الباب هذه بالكامل، ويمكن ضبط إنذار البطارية المنخفضة في نفس الوقت، ولكن يمكن أن تصل عمر البطارية إلى 4 إلى 6 أشهر دون القلق بشأن انقطاع الاستخدام.', 4812.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FPS56vNPTWomoes-tuya-smart-wifi-video-doorbell-camera-2-way-audio-intercom-outdoor-wireless-door-bell-night-vision-749933.webp?alt=media&token=2f029b61-b977-47ff-9988-45b9ccc9e23e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fxq26EfE0WP1.jpg?alt=media&token=a23e3e3d-6ac4-4f18-aeb3-e844f534a6d6", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FWXYOsXf62X2.jpg?alt=media&token=08501fa7-ebb9-450e-b46b-ede668758bf2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fa3vycVRd3v3.jpg?alt=media&token=9fdf502b-d434-4cef-be23-14b9b8a38f0c", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FAo3CSys6194.jpg?alt=media&token=92710f9a-2d23-40e3-8b40-ec761ab29e3e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FF5tfIG99t5moes-tuya-smart-wifi-video-doorbell-camera-2-way-audio-intercom-outdoor-wireless-door-bell-night-vision-218394.webp?alt=media&token=16c898c8-f23a-4822-a07e-a251f585eb8e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fp6GOxjDmMqmoes-tuya-smart-wifi-video-doorbell-camera-2-way-audio-intercom-outdoor-wireless-door-bell-night-vision-268975.webp?alt=media&token=34d1b0b7-5df1-40e4-b2ee-c6784bb639e3", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FLZeKWBLHkmmoes-tuya-smart-wifi-video-doorbell-camera-2-way-audio-intercom-outdoor-wireless-door-bell-night-vision-310172.webp?alt=media&token=cfed33af-8f02-4f9f-bb53-433149692595", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FUIoDXTykmymoes-tuya-smart-wifi-video-doorbell-camera-2-way-audio-intercom-outdoor-wireless-door-bell-night-vision-688424.webp?alt=media&token=4fcf2412-eb45-488c-9a59-4b27fd17175f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FwsUuTC7CAEmoes-tuya-smart-wifi-video-doorbell-camera-2-way-audio-intercom-outdoor-wireless-door-bell-night-vision-690363.webp?alt=media&token=26aeda87-4f79-42f7-a703-9db7b28f1a3d"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30074, 'HUB Tuya Wired ZIGBEE', 'HUB Tuya Wired ZIGBEE', 'يمكن توصيله بتطبيق "SmartLife" لتشغيل سهل عبر الهاتف الذكي، مثل إضافة الأجهزة، والمؤقت، والتحكم في المجموعات، وربط الأجهزة المتعددة، والمزيد. • التحكم في المجموعات: على سبيل المثال، يمكنك إنشاء مجموعة مع عدة منظمات حرارة ZigBee للتحكم في درجات حرارة الغرف المختلفة. • تأكد من أن هاتفك الذكي متصل بنفس شبكة Wi-Fi الخاصة بالبوابة لضمان اتصال فعال بينه وبينها. • بوابة ZigBee أكثر استقرارًا وسرعة من حلول Wi-Fi بفضل توافقها الواسع مع أجهزة ZigBee الذكية. • وظيفة التوقيت: تشغيل/إيقاف أجهزة ZigBee وفقًا لجدولك اليومي، مما يوفر لك المزيد من الطاقة والمال، ويقضي على هدر الطاقة الاحتياطية.', 3850.00, 30003, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FgTdG8F2eOr4102uv%2B8EML._AC_SX679_.jpg?alt=media&token=edd2ec10-b18b-43ab-a7ea-35e326f03186", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fz19Or2F5PX51v2btAm5yL._AC_SX679_.jpg?alt=media&token=bb004cc7-bdd4-4caf-ba38-fab26b4a3976", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FpfGJF073jB617GXV1US0L._AC_SX679_.jpg?alt=media&token=d1e4de05-8ad7-41de-9eb0-8f5f69285ca2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FP1Xltktbf561GbMMjANPL._AC_SL1000_.jpg?alt=media&token=467e8a26-6712-42fa-a2e8-145f5b74559e"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30072, 'Tuya Zigbee Water Sensor, Water Leak Detector', 'Tuya Zigbee Water Sensor, Water Leak Detector', '【ملاحظة】 يجب استخدام هذا المنتج مع بوابة زيجبي. لا يمكن استخدامه بمفرده بدون بوابة. • 💧 【كشف فوري】 مستشعر فيضان يكتشف تسرب المياه في البيئة فورًا. بمجرد وصول مستوى المياه المُراقَب إلى ارتفاع مُحدد مسبقًا، يُرسل الكاشف إشارة إنذار ويُبلغ هاتف المستخدم عبر تطبيق تويا/سمارت لايف، لتتمكن من مُتابعة الوضع واتخاذ الإجراءات المناسبة. • 💧 【كشف جديد】يعتمد على وحدة كشف مُتقدمة، حيث يستشعر المسطح المائي فورًا. عندما يتدفق الماء المُتراكم عبر أقطاب المسبار، يُرسل على الفور رسالة إنذار إلى البوابة. كما يُمكنك إغلاق منفذ المياه عن بُعد عبر هاتفك. 💧 【عمر بطارية طويل، تنبيه بانخفاض مستوى البطارية】يمكن تشغيل البطارية لمدة عام كامل (مع التذكير بانخفاض مستوى البطارية 20 مرة يوميًا)، ولكن انخفاض مستوى البطارية لا يسمح بإرسال تنبيه في الوقت المناسب. • 💧 【تطبيق متعدد الاستخدامات】يعمل كاشف تسرب المياه بكفاءة في المنازل والفنادق والمتاجر والمكاتب والشقق وغيرها من الأماكن. يمكنك استخدام مستشعر تسرب المياه لمراقبة تسرب المياه في أي وقت وضمان السلامة.', 1420.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F2AqROpVeRSH6271d82308f9428b842a4b21231b0350H.jpg_720x720q50.avif?alt=media&token=53cef00a-85f7-4453-9e72-47fea40d41ee", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FOUzaDGrnWaH3b33aa2a08a74f03aae91e787db41aefj.jpg_720x720q50.avif?alt=media&token=2dc5ccb9-2045-4b7c-b4db-b611fc4dd276", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FGvNPStlhCTH096e9592c1c64c28adcb2385679149a8f.jpg_720x720q50.avif?alt=media&token=64729ecb-bbd5-4607-bf5f-9b12262c9b46", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FGKfY4wLWUwH102d4cc735244507ae81b3dd549c148av.jpg_720x720q50.avif?alt=media&token=8cde5e14-9742-42c4-8541-a5f3ea6ec6a5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FUOovCkLvDTHc22fa8acf2544801b8e73b794c6022f9v.jpg_720x720q50.avif?alt=media&token=a224808a-44bc-42fa-a1fe-00f65cb3334e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fm6tO5qAtTRHf2d50482c39c45518f6c0e4fdd29813dX.jpg_720x720q50.avif?alt=media&token=eea7d717-86a5-4ac3-b016-46639563cd1f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FFjQGB7DaINS6fb8a9961716469f8ee548d0dbe25a854.jpg_960x960.avif?alt=media&token=f41a68ed-cfda-4de8-b479-dd3e56543db9"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30071, 'TUYA Water Leak Sensor Alarm WIFI', 'TUYA Water Leak Sensor Alarm WIFI', 'تنبيهات فورية لتسرب المياه: ما عليك سوى توصيل البوابة بشبكة واي فاي، وسترسل رسائل بريد إلكتروني وإشعارات وتنبيهات فورية إلى هاتفك عند حدوث تسرب للمياه حتى لو لم تكن في المنزل. أجهزة استشعار المياه SEHOMY والبوابة مُقترنة مباشرةً بمجرد إخراجها من العلبة. ملاحظة: تدعم شبكة واي فاي 2.4 جيجا فقط، ولا تدعم شبكة واي فاي 5 جيجا. • كشف تسرب المياه وتذكير فوري: عندما يكتشف كاشف المياه ذو خط الكشف 31.5 فيضان الماء، سيرسل إنذار المياه إشعارات وتنبيهات فورية إلى هاتفك المحمول من خلال التطبيق. سيُعلمك في الوقت المناسب ويتخذ الإجراءات اللازمة لحماية منزلك وممتلكاتك من أضرار المياه! بعد عودة المياه، سيتم إلغاء الإنذار. • سهولة التركيب والتشغيل: لا يتطلب أي كابلات معقدة، حيث أن مستشعر تسرب المياه SEHOMY المزود بشبكة واي فاي هو الحل الأمثل. ما عليك سوى وضعه بالقرب من الجهاز الذي ترغب في مراقبته أو تحته، ثم توصيل البوابة بشبكة Wi-Fi، ثم مسح الرمز ثنائي الأبعاد (Tuya smart أو smart life وفقًا لنظام الهاتف المحمول) في التعليمات. في حال وجود أي مشكلة، يُرجى التواصل معنا بحرية. سنقدم لك استبدالًا مجانيًا أو استردادًا للمال. • تذكير: يعمل بالبطارية وبطارية منخفضة: يستخدم بطاريتين AAA متعددتي الأغراض، سهل الشراء، وتدوم البطارية لأكثر من نصف عام، ويمكنك عرض طاقتها على التطبيق. كابل طويل لمستشعر كشف المياه لسهولة وضعه. • متعدد الوظائف: أجهزة كشف المياه مثالية جدًا للمنازل والمستودعات والأقبية، حيث تراقب باستمرار أي تسربات حول الأحواض. الاستخدامات المقترحة هي بالقرب من أو تحت مضخات المجاري، والمراحيض، وسخانات المياه، والغسالات، وغسالات الأطباق، والأحواض، وأحواض الأسماك، وأي مكان آخر معرض لتسربات المياه والفيضانات.', 1350.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FKhLHa7rwAW61NY0G5hf%2BL._AC_SL1500_.jpg?alt=media&token=542c123d-a59e-40f4-8839-a31dcb6f47e1", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FBWn6DsWcoF61HbBfvE59L._AC_SX679_.jpg?alt=media&token=c25ef0f1-1336-42d8-abb3-7a42df3cd043", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FTJTbtn56Ho61UaKDerNrL._AC_SX679_.jpg?alt=media&token=8a8b4403-a32a-4300-8c5f-e83261418b11", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FldgmJx3t6P61XHbd5B2sL._AC_SX679_.jpg?alt=media&token=d9e09a42-1e8a-4b14-a10c-5874509fd5d8", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FafTdQ2SXeH71LLYb3ldxL._AC_SX679_.jpg?alt=media&token=46f10452-d245-4512-a7b2-43dd4530f1ab", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F0aUKX0KNEL81kxD2MArBL._AC_SL1500_.jpg?alt=media&token=50c4db99-b8e0-4854-ab04-248f0bdf9b5e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FhYD5qujnQc810XUcNIYcL._AC_SX679_.jpg?alt=media&token=b2d64a5d-4912-49da-bdfc-0588542baacd"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30070, 'Temperature Sensor ZIGBEE', 'Temperature Sensor ZIGBEE', '• 【الدقة】: مستشعرات مدمجة لدرجة الحرارة والرطوبة. مستشعر درجة الحرارة من -20 درجة مئوية إلى 60 درجة مئوية، ومستشعر الرطوبة من 0% إلى 100%. دقة قياس درجة الحرارة ±1 درجة مئوية، ودقة قياس الرطوبة ±5%. يتم التحديث كل دقيقتين لمزيد من الدقة. • 💧 【تفعيل الأتمتة】: راقب بيانات درجة الحرارة والرطوبة في أي وقت ومن أي مكان. يمكنك طلب درجة حرارة ورطوبة الدفيئة من خلال المساعد الذكي. على سبيل المثال: "ما هي درجة الحرارة، شكرًا لك؟" (يتطلب بوابة زيجبي). • 💧 【الارتباط الذكي】: يمكن تحقيق اتصال المنزل الذكي عبر تطبيق الهاتف المحمول. عند تغير البيئة المحيطة، يمكنك إجراء اتصال ذكي. على سبيل المثال، عندما تتجاوز درجة حرارة الغرفة 35 درجة مئوية، يتم تشغيل مكيف الهواء ويعود تلقائيًا إلى درجة الحرارة المحددة. عندما تكون الرطوبة أقل من 20%، يقوم جهاز الترطيب برش الهواء. يمكنك إنشاء بيئة ذكية خاصة بك. 💧 【تخزين وتصدير بيانات مجاني】: يدعم مقياس الرطوبة الداخلي تصدير البيانات وتخزينها لمدة عام. يمكن تنزيل السجلات بسرعة وسهولة باستخدام هاتف ذكي، ثم تصديرها كملف CSV عبر البريد الإلكتروني. • 💧 【سهل التركيب والاستخدام】: يمكنك ببساطة لصقه على الحائط باستخدام ملصق لسهولة التركيب والحمل والحجم الصغير. سهل التركيب وتكوين التطبيقات لسهولة التحكم. • 💧 【تصميم صغير ومحمول】: يبلغ قياس مقياس الحرارة الذكي المزود بمستشعر الرطوبة 71 × 25 × 20 مم، مما يوفر المساحة ويسهل حمله.', 1640.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F07TXcn27uCSmart-Temperature-And-Humidity-Sensor-APP-Remote-Monitor-For-Smart-Home-Wifi_3dc4f3c6-a500-405e-b19d-f15c2a06283d.4a0ba92822147e76462b96b1eaab5c75.webp?alt=media&token=3c4e76c8-4e77-4463-8481-8cb4897f42fc", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F4sscclhr4Q41%2BBe0x7cEL._SL1001_.jpg?alt=media&token=e5abac84-3047-4d24-a079-725d75b2e943", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FurhGcnFYCd41%2BdfhyMrdL._SX522_.jpg?alt=media&token=7a6ebf88-8dba-408d-8e11-efe9dcb880c7", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FdEvKS5bJAE41WN2rCzNKL._SX522_.jpg?alt=media&token=b1a0d967-e3c1-4c33-bb14-8663a15fd8d4", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F24nOtfZ8fC51b6o7ULlsL._SL1001_.jpg?alt=media&token=eeba9fb6-abab-4abd-8698-927c7eff9514", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FptkFNn4UAw61-MXk5wpzL._SX522_.jpg?alt=media&token=c7beed63-8b99-46ad-b1a3-3a75fdefc97f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FZEguIxMsav71J3XqBVRKL._SL1001_.jpg?alt=media&token=59002ad1-adb3-4b7f-8e72-b105376c17fa"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30069, 'MOTION SPOT DIRECT ZB SMART MINI PIR', 'MOTION SPOT DIRECT ZB SMART MINI PIR', 'مستشعر وجود بشري بتقنية الموجات المليمترية (mmWave)، قادر على كشف الأشخاص في الغرفة، سواءً كانوا ساكنين أو يقومون بحركات طفيفة أو كاملة، مما يوفر كشفًا دقيقًا لوجود أو غياب الأشخاص في المنطقة، مع إمكانية كشف الأشخاص النائمين. • متوافق مع جوجل هوم وأليكسا ومساعد المنزل من خلال بوابة ZigBee و/أو تكامل تطبيق SmartLife مع Tuya.', 2000.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FNqD4goRUjvHe7694fd4555c434baae83f900ffc6d99c.jpg_720x720q50.avif?alt=media&token=42f08b59-21b1-4673-8627-4e73a5f2b3d1", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FuoHRZ5s1TaSmart-Life-Zigbee-Human-Presence-Detector-Tuya-Wifi-MmWave-Radar-Pir-Montion-Sensor-With-Luminance-Detection.jpg_640x640.jpg_42a7f0e0-e597-461b-8a65-3c30c7192d6d_639x639.webp?alt=media&token=75f15eca-fee9-406e-9df6-9824184e88fa", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FXWIBF6IBqqH755a166646694fcd9b362e2aa8e6fb3ev.avif?alt=media&token=48f3a9a7-4774-4385-875a-ef97c57f8a23", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FZQzcgHfGVNHb7e91cc78c7e4f1ab099509f61eaac630.avif?alt=media&token=f64582b7-9778-4a7a-b90c-938a7ca1bd0f"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30068, 'Tuya Smart Human Presence Sensor Wifi PIR Motion Sensor', 'Tuya Smart Human Presence Sensor Wifi PIR Motion Sensor', '• تقنية الموجات المليمترية المتطورة للرادار 24 جيجا: تكتشف وجود الإنسان ضمن نطاق 10 أمتار، مما يوفر أداءً موثوقًا ودقيقًا في بيئات متنوعة باستخدام تقنية الميكروويف المتطورة. • تكامل تطبيق الحياة الذكية: يتصل بسلاسة بتطبيق الحياة الذكية، مما يسمح لك بإنشاء مشاهد مخصصة وأتمتة الإجراءات لمزيد من الراحة. • كشف شدة ضوء الخلية الضوئية: يراقب مستويات الإضاءة المحيطة ويمكّن من إنشاء المشهد بناءً على شدة الضوء (0~2500 لوكس)، مما يحسن الأتمتة ليلًا ونهارًا. • إنشاء مشهد متعدد الاستخدامات: خصص تجربة منزلك الذكي من خلال إعداد الإجراءات التي يتم تشغيلها بواسطة الحركة أو التغيرات في شدة الضوء، مما يجعل مساحتك أكثر استجابة لاحتياجاتك. • إعداد اكتشاف المسافة: بالإضافة إلى شدة الضوء، يسمح لك الجهاز بتعيين مسافات الكشف القصوى والدنيا لتشغيل الإجراءات. بالإضافة إلى ذلك، يمكن للمستشعر تتبع المسافة الدقيقة للشخص عند اكتشاف الحركة وعرضها في التطبيق. • ملاحظة: يعمل مستشعر الوجود البشري هذا عبر منفذ USB، ويتطلب اتصال واي فاي بتردد 2.4 جيجاهرتز؛ غير متوافق مع شبكات 5G.', 1665.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FNCeoPrvVfC1.jpg?alt=media&token=181d9444-f1fd-49b2-8738-18ad75e67c3e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FcoFQ0hsYKm2.jpg?alt=media&token=7ab81662-4906-4921-b43f-ef0f8b7e6f66", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FYHT7QKM4pX3.jpg?alt=media&token=768359e2-927b-452d-ac46-a54d002e3f05", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FRsID04o7hN4.jpg?alt=media&token=6a3edf31-b5bb-4ae8-8f98-e195b00b3b66", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fiz0Tl6vSDB5.jpg?alt=media&token=7046f993-72ce-454b-921c-dc916fb5d571", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FvSwyxeOBZR6.jpg?alt=media&token=736caa0a-a28f-4b64-a511-1246fcde8702", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FE2FsnQJwUi7.jpg?alt=media&token=465dab54-504b-4e76-847c-a9c1613a1586"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30067, 'MOTION SENSOR TUYA BATTERY +USB WIFI', 'MOTION SENSOR TUYA BATTERY +USB WIFI', 'مستشعر حركة لاسلكي، كاشف حركة داخلي، مع إشعارات داخل التطبيق. أنشئ مشاهد أتمتة لتشغيل وإيقاف مصابيح الإضاءة الذكية أو مفاتيح الواي فاي. الميزات التقنية: مستشعر حركة لاسلكي، طراز PIR-W، جهد الدخل: USB 5 فولت/2 أمبير، لا يُستخدم مع البطاريات العادية، فقط مع بطارية قابلة لإعادة الشحن. البطارية: 3 فولت تيار مستمر، بطاريتان AAA، تيار الاستعداد: 75 ميكرو أمبير، تيار التنبيه: 60 مللي أمبير، إشعار انخفاض الجهد: 2.2 فولت، واي فاي: 2.4 جيجاهرتز، 802.11b/g/n، مسافة الاستشعار: 6 أمتار، زاوية الكشف: 3 أمتار، الحد الأقصى للتركيب: 60 درجة مئوية. طريقة التركيب: على الحائط أو السقف. درجة حرارة التشغيل: -10-50 درجة مئوية. رطوبة التشغيل: 95% رطوبة نسبية.', 1395.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F8Y8HI0I7gH0264887.Jpg?alt=media&token=f4d4b180-5d80-48eb-958c-f23b5f9ca452", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F9A5fKppNth7127ab7b-73e2-4c54-909a-14840533614d.jpg?alt=media&token=ce9a43b2-118f-4d4c-81c0-e9d574a0cf09"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30065, 'TUYA GAS SENSOR ZIGBEE PLUG', 'TUYA GAS SENSOR ZIGBEE PLUG', '• تحذيرات عالية الجودة:يتميز بصوت تحذير 70 ديسيبل ومستوى تحذير 6% LEL، مما يضمن الاستجابة السريعة. • تطبيق تuya/حياة الذكية:يمكنك إدارة الجهاز من خلال تطبيق Tuya/Smart Life، مما يعزز الأمان الذكي. • الكشف عن الغاز الطبيعي:يستخدم هذا الجهاز للكشف عن الغاز الطبيعي، مما يوفر حماية فائقة للمنزل. • توافق مع الأجهزة الأوروبية : يوفر مدخل الكهرباء الأوروبي، مما يجعله متوافقًا مع الأنظمة الأوروبية. • الاتصال بالإنترنت دون جهاز:يدعم WIFI 2.4G، مما يسمح بالاتصال المباشر دون الحاجة إلى جهاز واجهة', 1800.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FbiEhVbkyAV17323464499f3ce72c838.webp?alt=media&token=1b5e0a98-6ef0-4176-9e7b-af0ff97d5409", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FDAf1P4A40W17323464496f5e56a0bd0.webp?alt=media&token=e89f8d7c-ff91-40cf-976b-c669931ed58d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FSgi5jL1zqM17323464490e5b30acd3e.webp?alt=media&token=32310ca3-3818-4c79-8ae5-283ffdac321f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F1NuSuAPYDl1732346449aa823083516.webp?alt=media&token=6e6b058c-073a-4be5-b408-10ae29d14435", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FSmqGfNKGRa17323464499121736163c.webp?alt=media&token=50e3a8a3-25f1-4ee2-b87a-4541fc468a4c", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FiAM3h3HFVE17323464490349f46d0ee.webp?alt=media&token=45322c8b-a8e5-45e8-bbec-ebbf489d6891"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30066, 'MOTION  SENSOR TUYA BATTERY ZB SMART MINI PIR', 'MOTION  SENSOR TUYA BATTERY ZB SMART MINI PIR', '• ضبط مستشعر الضوء: يستخدم المستشعر تقنية الأشعة تحت الحمراء السلبية، ومستشعر حركة PIR لتشغيل/إيقاف الأضواء تلقائيًا. يحتوي مستشعر الحركة هذا على مؤشر LED ساطع عندما يكتشف المستشعر الحركة. • كاميرا الاستشعار: مستشعر حركة سقف عالي الحساسية 120 درجة مع مسافة اكتشاف تصل إلى 5 أمتار. • مريح وبأسعار معقولة: - قم بتشغيل/إيقاف الإضاءة عند الحركة في غرفك، يوفر مفتاح مستشعر الحركة هذا المزيد من الراحة لك ولأفراد عائلتك في الحياة اليومية، كما يوفر الطاقة لعائلتك. • لضمان سلامة أفراد الأسرة، فهو مناسب لكبار السن. قم بتوصيل جهاز الإنذار الخاص بك لتشغيل تحذير. يجعل المظهر النحيف والمسطح هذا المستشعر سريًا، ولكنه يحمي منزلك على مدار الساعة طوال أيام الأسبوع. • التطبيقات: - يعمل عن طريق اكتشاف الأشعة تحت الحمراء لحركة الإنسان، ويمكن استخدام مستشعر الإشغال المثبت على السقف في المرآب، والممر، والطابق السفلي، والسلالم، والمطبخ، وغرفة المعاطف، والطابق العلوي... للاستخدام الداخلي، يرجى تثبيت مستشعر الإشغال في مكان محمي من أشعة الشمس المباشرة وأي مطر.', 1915.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fq9DLjaR9wK41NIsL9CZ4L._AC_SX679_.jpg?alt=media&token=46fca05e-236d-4ea6-93d7-8dce69d77f12", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fub3K577QU021mMv5rdcZL._AC_.jpg?alt=media&token=13011771-3044-435f-91f4-819b3a37302e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FcPzbeXigU551pTtdM2eoL._AC_.jpg?alt=media&token=f1bda3c6-a1ff-4889-828a-8dde590c63fa", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fyb6TwXdqQN61yoeHZ179L._AC_SX679_.jpg?alt=media&token=97b29f04-5b74-4b79-890d-e59730bdb3ad"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30062, 'CURTAIN REMOT', 'CURTAIN REMOT', 'YK2169-9C هو جهاز تحكم عن بُعد لنقل إشارة التردد اللاسلكي بتردد 433.92 ميجاهرتز ووضع تعديل OOK. يتميز المنتج بنافذة عرض رقمية من 8 أجزاء، تعرض ما مجموعه 9 قنوات من 0 إلى 8. يمكن التبديل بين القنوات المختلفة بسهولة بالضغط على الزر، ويمكن تنفيذ إجراءات مختلفة عند استقبال جهاز الاستقبال لقيم رمز مختلفة.', 600.00, 30003, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FQo7wADrYlpsmart-rf433-transmitter-remote-for-curtain-255850.webp?alt=media&token=9baabca1-241a-414b-9b05-e6d14732da24", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FQFtoYdnIm59-1-channel-rf433-remote-controller-for-controlling-wifi-curtain-switch-rf-roller-blinds-module-battery-powered-curtain-accessories-emitter-291664.webp?alt=media&token=15cd6ed5-b606-47c5-88fb-5dc45220c17c", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FMdAZ0dTienffljbkj.webp?alt=media&token=fffc7c2c-5b4a-4929-80ac-af24f7d468a1"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30063, 'SMART PLUGE WIFI', NULL, 'يعمل Amazon Smart Plug مع Alexa لإضافة التحكم الصوتي إلى أي مقبس كهربائي. • سهل الإعداد والاستخدام - وصّله، وافتح تطبيق Alexa، وابدأ العمل في دقائق. • متوافق مع العديد من المصابيح والمراوح وآلات صنع القهوة وغيرها من الأجهزة المنزلية المزودة بمفتاح تشغيل/إيقاف فعلي. • تصميم صغير الحجم يُتيح لك استخدام مقبس كهربائي ثانٍ لمقبس ذكي إضافي. • لا ​​حاجة لمركز منزلي ذكي. أدر جميع مقابس Amazon Smart Plugs الخاصة بك عبر تطبيق Alexa. • أنشئ روتينات تُؤتمت المهام اليومية مثل تشغيل الإضاءة أو تحضير القهوة. • موثوق - يُعيد الاتصال تلقائيًا بأليكسا بعد انقطاع التيار الكهربائي/شبكة Wi-Fi.', 800.00, 30006, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FXVpLr716Gds-l1600.webp?alt=media&token=d7280d99-1d45-40b6-9ea8-edd495efb426"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30064, 'Tuya Smart Gas Heat Sensor', NULL, '• مصدر الطاقة: منفذ USB صغير + 5 فولت/1 أمبير • الاستهلاك: أقل من 200 مللي أمبير • كشف الغاز: غاز طبيعي (CH4)، غاز مسال (LPG) • بيئة العمل: من -10 إلى 55 درجة مئوية • العينة: انتشار • النطاق: من 0 إلى 100% من الحد الأدنى للانفجار • قيمة ضبط التنبيه: 6% من الحد الأدنى للانفجار • التسامح: +- 3% من الحد الأدنى للانفجار • زمن الاستجابة: أقل من 30 ثانية • قيمة تنبيه الحرارة: 57 درجة مئوية • مستوى صوت التنبيه: أكثر من 70 ديسيبل • مخرج محرك الصمام/المناول: 12 فولت/300 مللي أمبير لمدة 15 ثانية • وقت الإحماء: 180 ثانية • عمر المستشعر: 5 سنوات • واي فاي: 2.4 جيجاهرتز IEEE802.11b/g/n • الأبعاد: 86 × 86 × 24.5 مم', 1800.00, 30007, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fv1KUFZjJWS1.avif?alt=media&token=aded63bc-30f0-4d26-817a-89977a6aed04"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30060, 'MINI SWITCH ZIGBEE AVATTO', NULL, 'Smart Switch Module (ZWSM16) • وحدة مفاتيح إضاءة صغيرة جدًا، قابلة للتركيب يدويًا: هيكل مدمج بأبعاد 39×39×19 مم، متوافقة مع 95% من صناديق التركيب المتوفرة في السوق. • التحكم عن بُعد عبر التطبيق: استخدم تطبيق Smart Life/Tuya Smart على هاتفك أو جهازك اللوحي للتحكم بسهولة في مفتاح الإضاءة من أي مكان وفي أي وقت. • التحكم الصوتي بدون استخدام اليدين: متوافق مع Amazon Alexa Echo وGoogle Home، إلخ. يمكنك التحكم في مفتاح الإضاءة بسهولة باستخدام صوتك. • المؤقت والجدول الزمني والعد التنازلي: خصص الجداول الزمنية والمؤقتات والعد التنازلي لتنظيم حياتك اليومية بذكاء. • سهلة التركيب: تتناسب وحدة المفاتيح صغيرة الحجم مع صناديق تركيب المفاتيح أو المصابيح بسهولة. (ملاحظة: افصل الكهرباء أثناء التركيب). • التحكم ثنائي الاتجاه: يمكنك ترقية مفاتيح التحكم ثنائية الاتجاه دون تغيير تصميم أسلاك المنزل. • 3 أنواع من المفاتيح للاختيار من بينها: اختر بين مفتاح هزاز قابل للقلب لتغيير الحالة، ومفتاح متزامن، ومفتاح إعادة الضبط الذاتي. • وظيفة ذاكرة الحالة: اضبط حالة المفتاح عند انقطاع التيار الكهربائي، ثم أعدها إلى وضع التشغيل أو الإيقاف أو إلى الوضع السابق. • وظيفة القفل المتداخل: تفعيل قناة واحدة فقط في كل مرة، وإيقاف القنوات الأخرى في آنٍ واحد. • وظيفة التحكم الجماعي: تجميع عدة مفاتيح في غرف مختلفة لسهولة التحكم الجماعي. • وظيفة مشاركة العائلة: شارك المفتاح مع أفراد عائلتك، وكوّنوا معًا منزلًا ذكيًا. • وظيفة الربط: اربط مع وحدات المفاتيح الأخرى، وأجهزة الاستشعار، والأجهزة المنزلية لإنشاء أوضاع مختلفة، مثل وضع النوم، ووضع العمل، ووضع العشاء، ووضع العودة إلى المنزل، إلخ.', 1000.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FJZwYTWSUbX%D8%A7%D8%A8%D8%A7.webp?alt=media&token=ece762e7-a072-4d03-831f-4d60e4bad1ba"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30061, 'MINI SWITCH WIFI', NULL, 'تحكم متعدد الاستخدامات: تتيح أوضاع WiFi وRF التحكم عن بعد لاسلكيًا عبر تطبيق الهاتف الذكي أو جهاز التحكم عن بعد 433. جهاز التحكم عن بعد: يدعم Alexa/Google Home/Smart Life، والذي يمكن ربطه واستخدامه. حتى لو نسيت إطفاء الأضواء بعد الخروج، يمكنك التحكم بها على هاتفك المحمول والتحقق من حالة الجهاز في أي وقت. مظهر مضغوط: مناسب لصناديق مفاتيح الحائط، ويمكن إخفاؤه بسهولة في صندوق مفاتيح الحائط المخفي للمفاتيح التقليدية دون التأثير على نمط الديكور الأصلي، مما يجعله ذكيًا. علاوة على ذلك، لا تحتاج إلى استبدال المفتاح الأصلي الخاص بك لاستخدامه بشكل طبيعي وظيفة التوقيت والذاكرة: يمكن إنشاء جداول التبديل باستخدام الهاتف الذكي. سيتم بعد ذلك تشغيل الجهاز وإيقافه تلقائيًا كما هو مقرر. حتى لو تمت استعادة مصدر الطاقة بعد انقطاع التيار الكهربائي في المنزل، فلا داعي للقلق بشأن تغيير حالة الجهاز، ويمكن استعادته إلى آخر حالة تم استخدامها. سعة عالية: تم تصنيفها لأحمال 16 أمبير، ومناسبة لمختلف دوائر الإضاءة والأجهزة', 875.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FYhGOaxjGDB1Z.webp?alt=media&token=75c3db18-766e-4e37-893a-9ec4b257f2c5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FIIihIH5nL52.jpg?alt=media&token=80c9e2ff-34c3-45e0-8bcf-2663579563f9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F6dtSiTkTRk3.jpg?alt=media&token=137cf046-20bc-4507-8393-eb84c714b713", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FzYAtSfFxZn4.jpg?alt=media&token=450d0618-dd48-4fee-a953-17a5f299e240", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FA1borlrf6l5.jpg?alt=media&token=a2e7c83c-06c8-439a-8803-975eb03b1aef", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fu7UqkrSBb56.jpg?alt=media&token=26380a9c-3af8-4a2e-8835-dcc744901e47", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FZY282LsqdO7.jpg?alt=media&token=3f02fb61-c6e2-4a21-b6db-e185a1bc418a"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30058, 'Switch Black ZIGBEE', NULL, '[التحكم عن بعد من خلال التطبيق] - يمكن التحكم في مفتاح Zigbee بعد توصيله بمحور Zigbee عبر تطبيق Smart Life TUYAعلى الهاتف والكمبيوتر اللوحي. • [التحكم الصوتي] - مفتاح إضاءة Zigbee متوافق تمامًا مع Amazon Alexa وGoogle Home، فقط أمر بسيط لتشغيل/إيقاف تشغيل الضوء وتعيين الجدول الزمني. • [وظيفة المشاركة العائلية] - شارك مفتاح الإضاءة مع أحد أفراد عائلتك عبر تطبيق Smart Life بصلاحيات محدودة. تحكم في منزلك مع عائلتك معًا بطريقة آمنة. • [وظيفة التوقيت] - اضبط الجدول الزمني على المفتاح، وقم بتشغيل/إيقاف تشغيل الضوء وفقًا لجدولك الزمني. كما أن المفتاح يحتوي على توقيت إضافي، وعد تنازلي، ووظيفة تدوير، وعشوائية، ووظيفة الزحف. • [وظيفة التحكم في الربط والمجموعة] - يمكن ربط مفتاح الإضاءة بمفتاح آخر في منزلك، بالإضافة إلى جهاز منزلي ذكي آخر. خطوة واحدة لتحقيق أمر معقد. مما يجعل إنشاء مشهد مغادرة المنزل، ومشهد العودة إلى المنزل ومشهد النوم وما إلى ذلك ممكنًا. • [وظيفة حالة التتابع] - بعد انقطاع التيار الكهربائي، يتوفر 3 خيارات للاختيار من بينها عند استعادة الطاقة: تشغيل/إيقاف التشغيل/تذكر آخر حالة. • المواصفات • --الجهد: 100 فولت أو 220 فولت • --التردد: 50/60 هرتز • --طاقة الحمل: 3-400 واط • --اللاسلكي: Zigbee 3.0 • --مادة الغلاف: لوحة زجاجية • --حجم المنتج: 120*72*33 مم', 1875.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FH8CHWERDfD%D8%AC%D8%AC%D8%AC.jpg?alt=media&token=1a4cce07-18d9-4593-bcb1-d6bf07792192"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
