INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30057, 'Swich White WIFI', NULL, '1.【ملاحظة】لا حاجة إلى سلك محايد فقط لدائرة القطب الواحد؛ يجب أن تكون القوة الكهربائية للمصباح أكبر من 5 واط. يدعم شبكة 2.4 جيجاهرتز فقط؛ قم بتركيب المكثف في العبوة للعمل بشكل صحيح. وضع اقتران أسهل بكثير لإضافة الجهاز مع اتصال واي فاي وبلوتوث. 2.【وضع التحكم في عدم التداخل】يسمح بالتحكم في المفتاح عبر التطبيق والتحكم باللمس والتحكم الصوتي وجهاز التحكم عن بعد RF433 مع ترميز 1527 (جهاز التحكم عن بعد RF433 غير متضمن في العبوة)؛ كل طريقة تحكم تعمل بشكل مستقل. 3.【جهاز تحكم عن بعد】متوافق مع اليكسا وجوجل هوم للتحكم الصوتي بدون استخدام اليدين؛ يمكن أيضًا التحكم فيه عبر تطبيق سمارت لايف/تويا في أي وقت وفي أي مكان. 4.【وظيفة التوقيت】تحكم كامل في الأجهزة المتصلة مع المؤقتات والجداول الزمنية والعد التنازلي (1/5/30 دقيقة، ساعة واحدة، إلخ.) مع التطبيق؛ شارك التحكم مع العائلة والأصدقاء لمزيد من الراحة. 5.【حالة المرحل】ميزات جديدة مثل حالة ترحيل التشغيل/الإيقاف', 1750.00, 30002, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FJ43wGDalvF\'\'\'\'.jpg?alt=media&token=2d9f1092-3fb5-463d-a8ef-6e449ed12222"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
