INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30055, 'GS-F8-4CH Smart screen 8 inch', NULL, '• لوحة تحكم Tuya Smart Home مع نظام موسيقى WiFi Zigbee Ble مع مكبرات صوت مركزي للتحكم في منزلك باستخدام لوحة التحكم الذكية Tuya: شاشة تعمل باللمس ودعم الأجهزة • Zigbee وإدارة الموسيقى والمزيد. لوحة التحكم القوية Tuya Smart Home هي جهاز • سيحدث ثورة في طريقة تفاعلك مع منزلك الذكي. بفضل شاشته التي تعمل باللمس مقاس 8 بوصات وتوافقه • مع WiFi وZigbee وBluetooth، يمنحك هذا الجهاز تحكمًا غير مسبوق في جميع أجهزتك الذكية. • مزود بـ 4 ميكروفونات مدمجة لإدخال صوت واضح ودقيق، تدعم اللوحة مجموعة واسعة من الميزات، بما في ذلك إدارة الموسيقى والتحكم في الطقس وتكوين السيناريوهات المخصصة. بفضل وظيفتها من بوابات Zigbee، تلغي الحاجة إلى جهاز إضافي وتسمح لك بتوصيل ما يصل إلى 100 جهاز Zigbee مباشرة من اللوحة.', 27000.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FD2Ea2xleh2Hea34a12ee36742f68edd1359f02044b6c.png_720x720q50.png?alt=media&token=5e0ce6d3-b093-4310-be72-0205deb373a5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F1RKi4x4gcrHd61d51a94df0499d91d6e108c4ecf4b7F.jpg_720x720q50.avif?alt=media&token=37ba7b22-6542-407b-a032-a1b44357a455", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FnZKDcEjK1hHbc8fbaf255cd48a792648b960479fd90m.jpg_720x720q50.avif?alt=media&token=4f05366e-635b-491f-ae35-2fa794f40fc7", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fp9vEMhzF57H56686135b9da4760be9265d31174487fp.jpg_720x720q50.avif?alt=media&token=67c6e801-7f99-44cf-9f5e-3cf5e8d2f92e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FduA4N27QzfH1079f9baa9864ad3b68d5d148d2831c5n.jpg_720x720q50.avif?alt=media&token=da55811f-522f-434c-9bd2-766a73cf7e1b", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FZO57J9q3K3H82d42640962e4f12b3405734ba897505m.jpg_720x720q50.avif?alt=media&token=0994f870-bca1-4d32-a4fb-47ad1433bfed", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F0twFLascDpH7a02561a54d34b688169378ce307da6b2.jpg_720x720q50.avif?alt=media&token=191ce9e4-ca14-49fa-b200-053193ce23b2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FRP8uPgb4AHH8bc03bf819d94437933ba3893ca16d06t.jpg_720x720q50.avif?alt=media&token=c63942c3-f984-4530-966b-83cd0b871939"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30054, 'GS-F8-2CH (2-way wired ceiling speakers + 2-gang relay switch) GS', NULL, '• 8 عبارة عن بوابة منزلية ذكية من Tuya مزودة بشاشة تعمل باللمس مقاس 8 بوصة ونظام تشغيل Android وتدعم تشغيل الموسيقى. • الميزات الرئيسية: • يأتي مع اتصال WiFi وLan، ZigBee 3.0، وأضاف 100 جهاز فرعي ومخرجين لسماعات أسبيكر • التحكم المحلي والمشهد الذكي المحلي • قم بتخصيص مشهد منزلك، بنقرة واحدة للتشغيل. • يمكن أن يدعم مكبرات الصوت السلكية والبلوتوث، وتشغيل الموسيقى على شاشة تعمل بلمسة واحدة • مفتاح ترحيل ثنائي العصا، يدعم مخرجين اسبيكر ,يدعم أضواء الأسلاك، والمراوح، وما إلى ذلك. • يدعم العمل مع جهاز زيجبي الفرعي، مثل مفتاح حائط زيجبي، لمبة زيجبي، موتو ستارة زيجبي', 26000.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fio5pnfFj0V1.avif?alt=media&token=90399457-0e24-40fc-821f-81efe92d7111", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FvlwszWEHrr2.avif?alt=media&token=06ba1cdf-a513-42ca-9bef-c23bd2db3fc9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FSnGPHgp5KM3.avif?alt=media&token=0716ee0b-6e6d-4c44-8b65-ecb2aaffbfb9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F9VsJtZEuxc4.avif?alt=media&token=7e7a70bd-4d4b-46b6-91d6-81222aede0bd", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fq06HPmgBaF5.avif?alt=media&token=ad61100b-9af9-46d5-b5dc-4b0f2fc06d38", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FkgWJ81oGwQ6.avif?alt=media&token=cbe27db9-bd23-499e-b025-e3add35087c1"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30053, 'Tuya 10.1-Inch Smart Control Panel Max with Ble/Zigbee Gateway', NULL, 'لوحة التحكم الذكية Tuya مقاس 10.1 بوصة Max بمثابة بوابة لأجهزة Tuya، مما يوفر تكاملاً سلسًا لمنزلك الذكي. تحتوي على جرس باب داخلي مدمج وكاميرا أمامية للمراقبة والتواصل في الوقت الفعلي. يتم تنشيط لوحة التحكم بسهولة دون لمس ولديها أجهزة مطورة وخيارات متعددة لإمداد الطاقة للحصول على أداء مثالي. إنها متوافقة مع أجهزة Tuya الأخرى ويمكن التحكم فيها عن بُعد من خلال تطبيق. ارتقِ بحياتك الذكية مع لوحة التحكم الذكية Tuya مقاس 10.1 بوصة Max.', 30500.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FtXC64LdwxXtuya-101-inch-smart-control-panel-max-with-blezigbee-gateway-924801.webp?alt=media&token=d425907d-bfd3-4731-8a0e-6a833d2ab44b", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FnyzIIDs8uMtuya-101-inch-smart-control-panel-max-with-blezigbee-gateway-622872.webp?alt=media&token=6dcb87fd-9ba9-4dbd-88c4-649203b2bf7f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FsogHGMB4fOtuya-101-inch-smart-control-panel-max-with-blezigbee-gateway-895769.webp?alt=media&token=12d85be4-9799-4a5b-a4ba-37f1d4f116f1", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FEIU9yblmVrtuya-101-inch-smart-control-panel-max-with-blezigbee-gateway-built-in-building-intercom-compatible-869583.webp?alt=media&token=83e63616-cfa2-4fe9-8081-ca2210b44f7f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F7FQ8Zq1Etrtuya-101-inch-smart-control-panel-max-with-blezigbee-gateway-123730.webp?alt=media&token=0f7b85e6-03e6-4b71-b566-e699402eb108", "https://firebasestorage.googleapis.co