INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30044, 'shiny-silver-i12-face-version-2498', NULL, '1فتح الباب في اي وقت بلمسه من خلال الابليكيشن موبايل دون الحاجه للضغط علي الجرس مع امكانية الغاء هذا الزر من الابليكيشن موبايل 2 فتح الكاميرا في اي وقت من خلال الابليكيشن موبايل و اجراء محادثة مع الشخص المتواجد علي الباب لمدة 55 ثانية مع التكرار مرات كثيره 3 من اهم االمكانيات الجديدة اضف المستخدمين من خلال الابليكيشن موبايل ) بصمة الوجه/بصمة الاصبع/الكارت/الرقم السري( 4 عند فتح الاوكره يدوي ترسل اشعار علي الموبايل 5 سهولة االضافه علي الواي فاي من خالل البلوتوث 6 امكانية عمل رمز شخصي للكالون داخل االبليكيشن يركب على االبواب الخشب والمصفحة يركب باالتجاهين يمين ويسار واي فاي 2.4 جيجا يعمل عن طريق الموبايل أ بلكيشن تويا وسمارت اليف بصمة وجه عين سحرية )كاميرا رؤية ليلية ألوان( يمكنك رؤية الشخص علي الباب فيديو مباشر والتحدث معه لمدة 55 ثانية عندما يضغط على الجرس مع التكرار مره اخره يفتح بي بصمة الاصبع والرقم السري والكارت )اي سي مايفير 13.56 ميجاهرتز( ومفتاح المعدني العادي للطوارئ شاشة داخلية 4.5 بوصة - يوجد نظام أمان لألطفال لعدم الفتح من الداخل امكانية جعل كلمة سرمؤقتة لفتح الباب من التطبيق )مع تك رارها( نسبة إستشعار البصمة 98.9 % سعة تخزين 300 مستخدم10 أدمن 50 بصمه وجه 240 بين بصمة أصبع وكارت و باسورد ناطق باللغة االنجليزية والعربية والصينية انذار ضد محاولة السرقة - انذار للعبث )اختياري( اضافة ريموت كنترول درجة حرارة العمل: 20- درجة مئوية إلى 70 درجة مئوية رطوبة العمل: الرطوبة النسبية %15~%93 موادالصنع : سبائك األلومنيوم مكسي ومطلي بطبقة زجاجية المعه يعمل بي بطارية7.4 فولت ليثيوم5000 ملي امبير – انذار النخفاض البطارية عمر خدمة البطارية أوقات فتح الباب حوالي3000 مرة كما يوجد مدخل بور للطوارئ كابل مايكرو يواس بي5 فولت 2 امبير في الابليكيشن تسجيل حتى 600 عملية دخول', 26400.00, 1, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FhYI9nHIoeJ1222222222.webp?alt=media&token=4f00b81f-c81c-4864-a875-7c53f5b3f67b"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
