INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30029, 'l03f1-2433', NULL, 'لباب الحديد والباب الخشبي اتجاه اليسار واليمين متوافق مع تطبيق TUYA WIFI 2.4 G وكلمة مرور مؤقتة لفتح الباب من التطبيق بصمة الإصبع، كلمة المرور، IC 13.56 ميجا هرتز بطاقة Mifare جهاز التحكم عن بعد بمسافة 7 أمتار مع العوائق و15 مترًا مفتوحًا (يأتي مع قطعتين من أجهزة التحكم عن بعد) (يمكن إضافة ما يصل إلى 30 جهاز تحكم عن بعد) مفتاح ميكانيكي للطوارئ سعة التخزين: 100 بصمة إصبع، و100 كلمة مرور، و100 بطاقة 9 منهم المشرف إنها محادثة باللغة الإنجليزية يعمل في البيئات الخارجية مع الأخذ في الاعتبار أنه لا يتلقى أمطارًا مباشرة بطارية 1.5 فولت × 4 بطاريات AA مصدر الطاقة 12 فولت، 2 أمبير: 5 أمبير يوجد مدخل طاقة طوارئ 5 فولت 2 أمبير Micro USB ويمكن توصيله بجهاز الاتصال الداخلي أو التحكم في الوصول', 8360.00, 1, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fg00m5GvQoNl03f1-2433.png?alt=media&token=6a2c6846-d794-49b1-a737-72f398afaa3a"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
