INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30011, 'ALEXA ECO DOT 5 Smart speaker with Alexa', NULL, 'أفضل نقطة صدى لدينا حتى الآن - استمتع بتجربة صوتية محسنة مقارنة بأي نقطة صدى سابقة مع Alexa للحصول على غناء أكثر وضوحًا وجهيرًا أعمق وصوتًا نابضًا بالحياة في أي غرفة. الموسيقى والمحتوى المفضل لديك - قم بتشغيل الموسيقى والكتب الصوتية والبودكاست من Amazon Music وApple Music وSpotify وغيرها أو عبر البلوتوث في جميع أنحاء منزلك. أليكسا سعيدة بالمساعدة - اطلب من أليكسا الحصول على تحديثات الطقس وتعيين مؤقتات بدون استخدام اليدين، والحصول على إجابات لأسئلتك وحتى سماع النكات. هل تحتاج إلى بضع دقائق إضافية في الصباح؟ فقط اضغط على Echo Dot لتأجيل المنبه. حافظ على راحة منزلك - تحكم في الأجهزة المنزلية الذكية المتوافقة بصوتك وروتينك الناتج عن أجهزة استشعار الحركة المدمجة أو درجة الحرارة الداخلية. أنشئ إجراءات روتينية لتشغيل الأضواء تلقائيًا عند دخولك إلى الغرفة، أو قم بتشغيل المروحة إذا تجاوزت درجة الحرارة الداخلية منطقة الراحة الخاصة بك. مصممة لحماية خصوصيتك – لا تعمل أمازون على بيع معلوماتك الشخصية للآخرين. مصمم بطبقات متعددة من عناصر التحكم في الخصوصية، بما في ذلك زر إيقاف تشغيل الميكروفون', 5500.00, 30005, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FpFlJ9fWDnYs-l1600%20(2).webp?alt=media&token=2e3fcf12-d1bc-4c5d-b788-155c4d23e0fc", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FILOEQMrxxds-l1600%20(1).webp?alt=media&token=c128cce2-ed86-4b05-80a9-c1c9c766b0c1", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FTmonQAGTzYs-l960.webp?alt=media&token=43be3658-157b-47ab-8763-c44c5e2dc78f", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FMGmaXCJ5pks-l140%20(5).webp?alt=media&token=41ff707c-b474-4dd2-9938-5331dde330ed"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30009, 'ALEXA ECHO DOT 5 WITHE CLOCK', NULL, 'أفضل نقطة صدى لدينا حتى الآن - استمتع بتجربة صوتية محسنة مقارنة بأي نقطة صدى سابقة مع Alexa للحصول على غناء أكثر وضوحًا وجهيرًا أعمق وصوتًا نابضًا بالحياة في أي غرفة. تحقق من الوقت والمزيد في لمحة - تعرض لك شاشة LED المحسنة الوقت والمنبهات والطقس وعناوين الأغاني والمزيد. الموسيقى والمحتوى المفضل لديك - قم بتشغيل الموسيقى والكتب الصوتية والبودكاست من Amazon Music وApple Music وSpotify وغيرها أو عبر البلوتوث في جميع أنحاء منزلك. Alexa جاهز للمساعدة - اطلب من Alexa أن يعرض لك الطقس وعناوين الأغاني، وضبط مؤقتات بدون استخدام اليدين، والحصول على إجابات لأسئلتك وحتى سماع النكات. هل تحتاج إلى بضع دقائق إضافية في الصباح؟ فقط اضغط على Echo Dot مع الساعة لتأجيل المنبه. حافظ على راحة منزلك - تحكم في الأجهزة المنزلية الذكية المتوافقة بصوتك وروتينك الناتج عن أجهزة استشعار الحركة المدمجة أو درجة الحرارة الداخلية. أنشئ إجراءات روتينية لتشغيل الأضواء المتوافقة تلقائيًا عند دخولك إلى الغرفة، أو قم بتشغيل المروحة إذا تجاوزت درجة الحرارة الداخلية منطقة الراحة الخاصة بك. مصممة لحماية خصوصيتك – لا تعمل أمازون على بيع معلوماتك الشخصية للآخرين. مصمم بطبقات متعددة من عناصر التحكم في الخصوصية، بما في ذلك زر إيقاف تشغيل الميكروفون. افعل المزيد مع إقران الأجهزة - املأ منزلك بالموسيقى باستخدام أجهزة Echo المتوافقة في غرف مختلفة، وأنشئ نظام مسرح منزلي مع Fire TV، وقم بتوسيع تغطية wifi مع شبكة eero متوافقة حتى تتمكن من قول وداعًا لعمليات الانقطاع والتخزين المؤقت. صديق للبيئة - لقد أخذنا في الاعتبار الاستدامة في تصميم هذا الجهاز مع عبوة قابلة لإعادة التدوير بنسبة 100%، وخيوط بوليستر معاد تدويرها بنسبة 100%، و55% من البلاستيك المعاد تدويره بعد الاستهلاك.', 6500.00, 30005, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FN9CQBMPJLms-l140%20(1).webp?alt=media&token=f6fd22c3-2152-476f-8ddd-8c5284795b94", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FSJXlXXEPE5s-l140.webp?alt=media&token=841b3e17-a2b1-4e42-85dd-88a16a02c247", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FyaFKw1out6s-l140%20(2).webp?alt=media&token=0bfedba0-5dbe-4b05-8639-9b2f626d9db0", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FZMps502S2Ls-l140%20(3).webp?alt=media&token=06df562a-9e7f-456f-bebb-f0188163f37e", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F8msuQU0pEGs-l140%20(4).webp?alt=media&token=7015f489-db05-4822-98b1-369fb20080fb", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fo37eL0Kpyss-l140%20(5).webp?alt=media&token=07d71f57-f3f3-435e-ba58-24697248555c"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30010, 'ALEXA ECO SHOW 5 5.5" HD Smart touchscreen, Camera:2MP', NULL, 'يجمع Echo Show 5 بين الراحة الذكية التي توفرها Alexa وشاشة مقاس 5.5 بوصة حتى تتمكن من عرض الأشياء لك، وكل ذلك في تصميم صغير جميل يناسب أي غرفة. اضبط المنبهات والمؤقتات، أو استرخ مع قائمة تشغيل مريحة، أو قم بإعداد روتين Alexa الذي يتحكم في الأجهزة الذكية المتوافقة مثل الأضواء وأجهزة تنظيم الحرارة لجدول زمني. قم ببث الموسيقى والعروض والبودكاست والمزيد من خدمات البث المفضلة لديك مثل Amazon Music وSpotify وPrime Video. وتحقق من عائلتك وأصدقائك وحيواناتك الأليفة باستخدام الكاميرا المدمجة. وكل ذلك بدون استخدام اليدين. تمت ترقية جهاز Echo Show 5 من الجيل الثالث بمعالج أسرع للحصول على استجابات أسرع، بالإضافة إلى نظام مكبر صوت محسّن للحصول على جودة صوت أعمق وأكثر ثراءً وتفصيلاً. اليكسا مع صور يتم تحسين الاستجابات الصوتية من Alexa من خلال صور واضحة على شاشة مقاس 5.5 بوصة. احصل على تحديث الأخبار، واضبط المنبهات والمؤقتات، وتحقق من حالة الطقس وحالة المرور، واحصل على أحدث مقطع دعائي للفيلم، وتصفح واستمع إلى الراديو والبودكاست والكتب الصوتية المسموعة والمزيد. كل ما عليك فعله هو أن تسأل. اختر من بين مجموعة مختارة من وجوه الساعة لمظهرك المفضل، وقم بإنشاء روتين الصباح الخاص بك لبدء يومك بالطريقة الصحيحة. الترفيه لكل جزء من يومك يمكنك متابعة آخر الأخبار وأبرز الأحداث الرياضية ومشاهدة المسلسلات التلفزيونية على خدمات الاشتراك مثل Prime Video واتباع الوصفات خطوة بخطوة. إنه الحجم المثالي لجلب كل هذا وأكثر إلى أي غرفة في لمحة. تواصل مع الآخرين قم بإجراء مكالمات بدون استخدام اليدين مع الأصدقاء والعائلة الذين لديهم جهاز Echo أو تطبيق Alexa (متوفر على نظام التشغيل Fire OS وAndroid وiOS وسطح المكتب). فقط اطلب من Alexa إجراء مكالمة مع أي شخص لديه جهاز مدعوم. ومع ميزة Drop In، يمكنك الاتصال فورًا بأجهزة Echo الأخرى في المنزل، على سبيل المثال لإرسال تذكير سريع لجميع أفراد العائلة في وقت واحد. تعزيز الخصوصية تم تصميم Echo Show 5 بطبقات متعددة من حماية الخصوصية. بدءًا من زر إيقاف تشغيل الميكروفون/الكاميرا وغطاء الكاميرا المدمج وحتى القدرة على حذف تسجيلاتك الصوتية، ستتمتع بالشفافية والتحكم في تجربة Alexa الخاصة بك. التحكم في الأجهزة الذكية المتوافقة استخدم Echo Show 5 لمشاهدة بث مباشر للكاميرا من غ', 7100.00, 30005, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FloKCEAvcrnalexa-echo-show-5.png?alt=media&token=0939634a-d56b-4b33-b413-106ae911e9fd", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FHwtHFpHT6Kshow_2.png?alt=media&token=00cbf46d-0a35-4f4e-a1fa-661c573ddf4d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FLDN1vvByloshow_1.png?alt=media&token=437120bf-99ad-4fc4-9992-3a0fd92bbff2", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F3BngCn1nfNshow_3.png?alt=media&token=3b282bd7-bb55-4c52-8270-e34336a74fe0", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FfFQYj9dn3Nshow_4.png?alt=media&token=b27cd3f0-cf49-4b07-a766-33d707ea25ab", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F6VM4VvLfUlshow_5.png?alt=media&token=735cf6d9-585e-421e-ab16-5c7173e58ef1", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FViiAoV4kWHshow_6.png?alt=media&token=ac79f852-f7c4-491d-a5f6-1047fad04d6b"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30008, '4 INCH TOUCH SCREEN', NULL, 'تسليط الضوء [مركز التحكم في المنزل الذكي] -- لوحة المشهد الذكية يمكنها التحكم لحكية والاخالي الألذة، المميس الذكي الضافتشعر الي الأضاءة في المشهد بلمسة واحدة. [بناء في محور لاسلكي igbee]-+ يمكن إضافة جهاز فرعي Zigbee , اقتصادي ومريح. [شاشة LCD متعددة اللمس عالية الدقة 4 بوصة] -- تجربة مستخدم عملية سولة ومريحة وسلسة لأفراد الأسرة. [مستشعر الكشف عن الضوء والمسافة] -- ضبط سطوع الشاشة تلقائيًا وفقًا للضوء المحيط، والاستيقاظ تلقائيًا عند اكتشاف الأشخاص الذين الديهم 20 ، قبل الشاشة، [جهاز تحكم عن بعد للتطبيق] -- يمكن التحكم في لوحة المشهد الذكية عبر تطبيق الحياة الذكية وتويا الذكي على هاتفك/جهازك اللوحي في أي مكان وزمان. [وظيفة مزامنة الجهاز الذكي]-يمكن مزامنة جميع الأجهزة الذكية في تطبيق tuya الذكي في بروتوكول مختلف في لوحة التحكم. [مستشعر الكشف عن الضوء والمسافة] -- ضبط سطوع الشاشة تلقائيًا وفقًا للضوء المحيط، والاستيقاظ تلقائيًا عند اكتشاف الأشخاص الذين لديهم 20 ، قبل الشاشة، [وظيفة المشاركة العائلية]-يمكنك مشاركة لوحة التحكم في ٥ المنزل الذكي مع عائلتك لإنشاء منزل ذكي مع أحد أفراد عائلتك. المواصفات -تشغيل الموسيقى: مدمج في مكبر صوت أحادي 1 واط ، تشغيل مصدر موسيقى محلي مخصص ، مصادر موسيقى عبر الإنترنت اختيارية. -مستشعر الضوء: ضبط سطوع الشاشة تلقائيًا وفقًا للمحيط المحيط. -مستشعر المسافة: تستيقظ الشاشة عند اكتشاف آشخاص في حدود 20 آلي -مركز زيجبي: نعم ، يمكن إضافة جهاز + زيجبي -الإدخال: 240VAC 50/60HZ 6A-100 كحد أقصى -بروتوكولات لاسلكية: واي فاي ، بلوتوث ، زيجبي -درجة حرارة العمل: C O° إلى + C 40®️ -رطوبالعمل: ، إلى RH 1.3 (بدون تكاثف) -أبعاد المنتج: 86x86x36mm -مسافة ثقب الترباس: 60 صى', 16500.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F7SzlQT9Dvrsmart-screen-4-inch.png?alt=media&token=5fd245a2-6417-4ada-b4ca-c1d12127d6d4", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FLRjVzdwY6IIMG_0733.jpg?alt=media&token=adcfe117-0e3e-41f3-8bc4-8a5f7ec73862", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FrhG6OKPoR1IMG_0732.jpg?alt=media&token=752e7814-9e1d-4795-bce2-25fe8c5922ed", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FPF3bzrifdLIMG_0731.jpg?alt=media&token=db6dd497-f709-4cc0-8e01-06d9117ade75", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FJNJQTU0O8FIMG_0730.jpg?alt=media&token=15f40e42-179f-48e9-bbd9-c82749437c1d"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30007, '5 INCH SCREEN', NULL, 'لوحة تحكم منزلية ذكية L ، لوحة ذكية 5 بوصة في الجدار مع أليكسا مدمجة , لوحة تبديل واي فاي لتطبيق تويا للحياة الذكية , شاشة تعمل باللمس للأتمتة المنزلية ، بوابة زيجبي مدمجة وشبكة بلي ، بيضاء [ مركز أتمتة المنزل الكل في واحد، تحكم حتى فئات المنتجات في شاشة واحدة. تستخدم لوحة المنزل الذكي TUYA حل Tuya loT للتحكم في الأجهزة الذكية المختلفة مثل الإضاءة والمفاتيح وأجهزة الاستشعار والمكيف وغيرها. يدعم إعداد المشهد والتحكم في المجموعة، مما يتيح لك التحقق بسمولة من وقت وتاريخ ودرجة حرارة وحالة أجهزتك الذكية على شاشتها. [ تدعم لوحة Alexa voice. تدعم هذه اللوحة التحكم بشاشة تعمل باللمس والتحكم الذكي بتطبيق الحياة والتحكم الصوتي من Alexa. باستخدام الأوامر الصوتية ، يمكنك ضبط أجهزة الإنذار، والتحقق من الطقس أو الأخبار، وتشغيل الموسيقى ، والتحكم في أجهزة اليكسا المنزلية الذكية الأخرى. قل ببساطة "اليكسا ، أنا في المنزل!" لتشغيل الأضواء والموسيقى والاستمتاع بتجربة منزلية سلسة. مفتاح واحد، حدد المشاهد والمجموعات على لوحة التحكم Control الذكية لتبسيط روتينك. لا مزيد من البحث عن أجهزة التحكم عن بعد في كل مكان. بنقرة واحدة فقط, سيظهر الضوء الدافئ والموسيقى الهادئة على الفور. هذه الميزة سولة الاستخدام بشكل خاص للعائلات التي لديها أطفال وكبار السن ، وكذلك الفنادق وبيوت الضيافة وغرف .المؤتمرات وبوابة شبكية متكاملة Zigbee وبوابة شبكية مدمجة Zigbee شبكة Bee متعددة الأوضاع توفر سيطرة محلية حتى عندما يتم قطع اتصال الإنترنت. يضمن أنه لا يزال بإمكانك التحكم في أجهزتك الذكية مع التحكم المحلي .حتى بدون اتصال بالإنترنت يتيح لك التحكم في كل من المفتاح القديم والأجهزة الذكية المنزلية من لوحة واحدة. التثبيت بسيط ، يتطلب تركيب سلك مباشر ومحايد', 18500.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FmpWVVgGvZ5smart-screen-5-inch.png?alt=media&token=acbe38d4-bd98-48d9-aa88-873850ced599", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FkSOALDXlrm71ecNT0UbQL._AC_SX679_.jpg?alt=media&token=0f30b20b-a1c2-4aca-abb4-91a13431a7ae", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FNJhgMqH4OJ71Z3KkCW9fL._AC_SX679_.jpg?alt=media&token=03e4bb6f-e7ae-47d7-b447-992a8ad4a2c9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FvCj5ePU5fm81jbLqr6NuL._AC_SX679_.jpg?alt=media&token=abe9af15-5295-415e-8c5e-d418fd7bce5a", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FDjrOaXrC9S81V3TIKdNqL._AC_SX679_.jpg?alt=media&token=8ebe7379-feea-4835-b77f-a02e495aff7c"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30006, '3.5 inch toutch screen', NULL, '3.5 بوصة Tuya المنزل الذكي متعدد الوظائف شاشة تعمل باللمس لوحة التحكم المركزية واي ڤاي الأشعة تحت الحمراء التحكم عن بعد التحكم الذكي في المشاهد الميزات: 1.جهاز تفاعلي متعدد الاستخدامات: شاشة اللمس الذكية عبارة عن جهاز تفاعلي متعدد الوظائف يدمج شاشة, وثلاثة أزرار مادية، وثلاث قنوات تتابع، وجهاز تحكم عن بعد بالأشعة تحت الحمراء.التحكم في العديد من الأجهزة المنزلية والمشاهد مباشرة من الشاشة، واستبدال المفاتيح التقليدية بقنوات التتابع للتحكم في الإضاءة. 2.نسبة الشاشة الكبيرة: يتميز لوحة التحكم المركزية بشاشة 3.5 بوصة، مما يعزز أكبر حجمًا، وأعلى نسبة من الشاشة إلى الجسم، وأقوى إطارًا في فقويته، مما يوفر تجربة عرضًا متفوقًا. 3.دقة لمس عالية: مجهزة بشاشة لمس سعوية بويكل GFF، يقدم مفتاح مشهد لوحة اللمس عالي الدقة وقدرات قوية ضد التدخل، مما بوفر وظيفة متعددة اللمس بشكل سلس وموثوق. 4.إضاءة المؤشر الأنيق: يتم معالجة أزرار لوحة التحكم المركزية الذكية مع عملية CMF التي تتضمن طلاء الورنيش والألوان والطلاء اللمسي بالأشعة فوق البنفسجية، مما يجعل تأثير الإضاءة الرائحة اللطيفة في الظلام. 5.تصميم الأزرار غير المتماثلة: يتميز لوحة التحكم بشاشة اللمس ٦ الوظائف بتصميم زر غير متماثل ثلاث مناطق، مكون من جزأين م. 不 مصابيح LED للتحكم عن بعد بالأشعة تحت الحمراء، مما يزيد من زيادى زاوية التحكم بالأشعة تحت الحمراء لإدارة الجهاز المحسنة يدعم أكثر من 110 فئات الأجهزة، وعدد محدود من الأجهزة والمشاهد، ويدعم 12 فئة من التحكم بالأجهزة بالأشعة تحت الحمراء. مواصفات: الأصل: البر الرئيسى للصين المدخلات: 100-240 فولت - 50/60 هرتز Wi-Fi, sigmesh, IR :بروتوكولات لاسلكية الحد الأقصى لإجمالي الحمل: 600 واط الحمولة القصوى لكل قناة: 200 واط درجة حرارة العمل: 0°ج - 40°ج رطوبة العمل: RH %90-%5 (غير مكثف) الحجم: 86*86*11.5 مم/3.39x339x0,45 بوصة (باستثناء القاعدة) 86*86*35.5 ملم (بما في ذلك القاعدة) حجم التعبئة: 95*95*48 ملم الوزن الإجمالي: 250 جرام ملاحظة: بسبب شاشة مختلفة وتأثير ضوئي، قد يكون اللون الفعلي للعنصرًا مختلفًا قليلاً من اللون الذي يظهر على الصور.شكرا لك! يرجى السماح 1-2 سم قياس الانحراف بسبب القياس اليدوي. شاشة تحكم مركزية xx', 11000.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FwAKJp4SF6tsmart-screen-3.5-inch.png?alt=media&token=bb0980c9-540c-420f-9d4b-491f0b372429", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FiKkQZxczrVIMG_0714.jpg?alt=media&token=37a04d2e-8363-4f32-be80-8fd3521355f0", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FwU3hqwEAfMIMG_0715.jpg?alt=media&token=d8f2eaa2-6644-4b28-824e-2c1428501f56", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FKsDhtCjPRwIMG_0716.jpg?alt=media&token=3777313d-14e7-4952-9113-48f1c915a6a3", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FfCJBiTPAsOIMG_0717.jpg?alt=media&token=85c1146d-e1fa-4da5-9fe0-2a63f82ae2b5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FwuQhrsTXZBIMG_0718.jpg?alt=media&token=bfeda121-5fa0-47f5-bd4c-db815cba851c", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FiSMEcbeWn3IMG_0719.jpg?alt=media&token=d57c2ccf-eb22-406f-932f-ac73a0c09a35"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30005, 'smart lock 840', NULL, 'الإصدار: تويا (واي فاي) 2، اللون اختياري: ذهبي القهوة 3، طرق فتح القفل: البطاقة + بصمة الإصبع + كلمة المرور + المفتاح الميكانيكي + التطبيق التحكم + NFC + التعرف على الوجه 4، الأبعاد الطول * العرض * الارتفاع: 403*81*55 مللي متر 5,نقر: [24*240 6068] 6، المادة: سبائك الألومنيوم 7، مناسبة لسمك الباب: 40-120 مم 8، مصدر الطاقة: بطارية ليثيوم 7.4 فولت 4200 مللي أمبير في الساعة، وقت عمل يصل إلى 182 يومًا (فتح 10 مرات/يوم) 9، السعة: 300 (الوجه + بصمة الإصبع + كلمة المرور + البطاقة)؛ عدد المسؤولين: 5 10، درجة حرارة العمل: -20 درجة مئوية ~ +60 درجة مئوية؛ رطوبة العمل: -10%-60% ر 11، الميزة: اتصال داخلي عبر الفيديو؛ فتح تلقائي بالكامل؛ كلمة المرور الافتراضية؛ كلمة مرور مؤقتة؛ تعديل وقت القفل تلقائيًا؛ إنذار إدخال الخطأ (5 مرات)؛ كاميرا رؤية مدمجة؛ التقاط تلقائي لجرس الباب', 16500.00, 1, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FOojISk3t8LIMG_0704.jpg?alt=media&token=d7dc2bd9-6cea-4046-8dd8-9592dcc2bb97", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FNwHTJovgUuIMG_0705.jpg?alt=media&token=e7e71e68-221b-42a4-8c26-3fc571947a5d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FDOiN3sfvIwIMG_0706.jpg?alt=media&token=5ee089e3-f4f0-40c1-b95f-6597eb79f32b", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F5xvcVndPoTIMG_0707.jpg?alt=media&token=7ea67038-3730-4381-a829-4696296ce720", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FbQjuHTAdO9IMG_0708.jpg?alt=media&token=03fbf9a5-c88c-4b59-a40f-f52e4f3dd80c", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F1016