INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30004, 'smart lock 824', NULL, 'الإصدار: تويا (واي فاي) 2، اللون اختياري: رمادي 3، طرق فتح القفل: البطاقة + بصمة الإصبع + كلمة المرور + المفتاح الميكانيكي + التطبيق التحكم + NFC + التعرف على الوجه 4، الأبعاد الطول * العرض * الارتفاع: 420*79*75 مللي متر\\\\\\\\\\\\ 5، نقر: [24*2406068] 6، المادة: سبائك الألومنيوم 7، مناسبة لسمك الباب: 40-120 مم 8 ، مصدر الطاقة: بطارية ليثيوم 7.4 فولت 4200 مللي أمبير في الساعة، وقت عمل يصل إلى 182 يومًا (فتح 10 مرات/يوم) 9، السعة: 300 (الوجه + بصمة الإصبع + كلمة المرور + البطاقة)؛ عدد المسؤولين: 5 10، درجة حرارة العمل: -20 درجة مئوية ~ +60 درجة مئوية؛ رطوبة العمل: -10%-60% ر 11، الميزة: اتصال داخلي عبر الفيديو؛ فتح تلقائي بالكامل؛ كلمة مرور افتراضية؛ كلمة مرور مؤقتة؛ تعديل وقت القفل تلقائيًا؛ إنذار إدخال الخطأ (5 مرات)؛ كاميرا رؤية ليلية مدمجة؛ التقاط تلقائي لجرس الباب', 15000.00, 1, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FiSiQdYDMLosmart-lock.png?alt=media&token=52bcd641-6dae-4ad5-bdce-49c42101ebeb", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FcnSu8d3lKyIMG_0700.jpg?alt=media&token=c6b33df0-1098-42b1-aad1-ec6117e0d458", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FL423nhWJdFIMG_0699.jpg?alt=media&token=d8150b64-df0f-4d84-a245-516dea0809e4", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FI3FWjnWxMjIMG_0702.jpg?alt=media&token=3bc1f6b2-8a78-4f7b-af65-e42f596e1db7", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F0KjHCV2aB6IMG_0701.jpg?alt=media&token=a5e0f8ce-2d4e-4971-a0f8-4e2575e7b02d", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_as