INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30003, '6 INCH TOUCH SCREEN WITH AMPLIFIER', NULL, '• لوحة لمس LCD ذكية متعددة الوظائف مقاس 6 بوصات للتحكم المركزي لأتمتة المنزل والتحكم في المشهد مع تطبيق Tuya يدعم أجهزة زيجبي WiFi • المميز: • •⁠ ⁠متوافق مع الصين| صناديق الحائط القياسية لجنوب شرق آسيا, بسيطة في تركيب الحائط. • •⁠ ⁠شاشة LCD عالية الدقة مقاس 6 بوصات، IP5، شاشة لمس متعددة، ميكروفون رباعي مع تقليل الضوضاء، مستشعر إضاءة تلقائي • •⁠ ⁠وظيفة بوابة زيجبي, جهاز التحكم عن بعد في التطبيق.بديل جيد لبوابة • الأخرى في المنزل، واستخدم لوحة التحكم مباشرة كل (on ) • لإضافة أجهزة Tuya ZigBee في التطبيق للتحكم الذكي، حتى 100 جماز • الفرعي المتوفر لتم إضافه on • •⁠ ⁠التحكم في الأضواء والستائر ومكيفات الهواء وجميع الأجهزة المنزلية الذكية الأخرى.قم بتكوين مشاهد Smart Home في التطبيق، قم بتشغيل وضع المشهد بلمسة واحدة على الشاشة. • •⁠ ⁠خدمج في مرحلتين والتي يمكنها التحكم في مفتاحين من أضواء الغرفة بشكل محلي. • •⁠ ⁠مستشعر الضوء: ضبط سطوع الشاشة تلقائيًا وفقًا للمحيطات. • المواصفات • •⁠ ⁠اسم المنتج: لوحة تحكم ذكية متعددة الوظاتف • •⁠ ⁠طاقة الإدخال: 100-240 فولت تيار متردد, 50/60 هرتز • •⁠ ⁠درجة حرارة العمل: C40-°CO° • •⁠ ⁠رطوبة العمل: RH %90-5 (غير مكثف) • •⁠ ⁠بروتوكول لاسلكي: واي فاي, زيجبي • •⁠ ⁠الأبعاد: 205.6x85.6x10 ملم (بدون قاعدة) 205.6x85.6x52 ملم • (مع القاعدة) • 2 مم (البعد القاعدة الخلفية) 60 مم (تو ) ) • فتحة الترباس). • تعليمات التثبيت: • •⁠ ⁠قم بإيقاف الطاقة الرئيسية في صندوق الكهرباء وتأكيد سلك النار لا يعيش مع قلم اختبار. • •⁠ ⁠قم بإزالة قاعدة Smart Switch وتتبيتها في صندوق الحائط. • •⁠ ⁠تحقق من الأسلاك وتأكد من أن الأسلاك في اتصال جيد مع الأطراف الطرفية ولا توجد أسلاك كوبر المكشوفة. • •⁠ ⁠اربط القاعدة إلى صندوق الحائط مع براغي تثبيت وتثبيت المفتاح الذكي مرة أخرى إلى القاعدة. • •⁠ ⁠ملاحظة أن لا ينبغي تثبيت البراغي ضيقة جدًا أثناء التثبيت في حالس نشوه أو أضرار الشاشة والأجهزة. • •⁠ ⁠إذا لم يتم تثبيت المفتاح الذكي المسطح بعد التثبيت، لا تضغط على الشاشة بعنفًا، يرجى التحقق من صندوق الحائط وتركيب القاعدة أولاً.', 26500.00, 30004, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F79GNSLFZEU1.jpg?alt=media&token=9e57d7f2-d93c-4a5d-acf3-74ffb9f04057", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FrzHpV1KY3NIMG_0721.jpg?alt=media&token=fa332bfb-5b5f-40f2-b5a9-4cc9cbd0b043", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FS3K5OlEELFIMG_0722.jpg?alt=media&token=f2d28daf-d807-42af-bfa3-a6711cba23b9", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FYJrj5U4zA3IMG_0723.jpg?alt=media&token=92eb44bd-8ba8-41d4-a041-7e76e17bf7a5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FHmg9T6jw4UIMG_0724.jpg?alt=media&token=6dd7cfab-dc26-4c6b-b575-e9167bd07e45", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fa8sRpGlbl2IMG_0725.jpg?alt=media&token=2906253e-697e-4d37-a992-77ce34564395"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30002, 'Smart Assistance', NULL, 'تعرف على ECHO SPOT - ساعة منبه ذكية أنيقة مع Alexa وصوت نابض بالحياة كبير. على استعداد لمساعدتك على الاستيقاظ، والاسترخاء، وأكثر من ذلك بكثير. ساعة ذكية قابلة للتخصيص - شاهد الوقت والطقس وعناوين الأغاني في لمحة سريعة، وتحكم في الأجهزة المنزلية الذكية، والمزيد. قم بإضفاء الطابع الشخصي على شاشتك باستخدام وجه الساعة المفضل لديك والألوان الممتعة. صوت نابض بالحياة كبير - استمتع بصوت غني مع غناء واضح وجهير عميق. فقط اطلب من Alexa تشغيل الموسيقى والبودكاست والكتب الصوتية. شاهد عناوين الأغاني والمس للتحكم في الموسيقى الخاصة بك. سهولة الاستخدام خلال اليوم - قم بإعداد روتين Alexa الذي يوقظك بلطف بالموسيقى والضوء التدريجي. ألق نظرة سريعة على الوقت أو تحقق من التذكيرات أو اطلب من Alexa تحديثات الطقس. حافظ على راحة منزلك - تحكم في الأجهزة المنزلية الذكية المتوافقة. فقط اطلب من Alexa تشغيل الأضواء أو لمس الشاشة لتعتيمها. أنشئ إجراءات روتينية تستخدم كشف الحركة لخفض منظم الحرارة أثناء خروجك أو فتح الستائر عند دخولك إلى الغرفة. مصمم لحماية خصوصيتك - لا تعمل أمازون على بيع معلوماتك الشخصية للآخرين. مصمم بطبقات متعددة من عناصر التحكم في الخصوصية بما في ذلك زر إيقاف تشغيل الميكروفون وعناصر التحكم داخل التطبيق مصممة للاستدامة الموديل: إيكو سبوت النوع: مكبر صوت ذكي حجم الشاشة: 2.83 بوصة تعمل باللمس الدقة: 240 × 320 بكسل الذاكرة: 1 جيجا بايت رام + 8 جيجا بايت eMMC توافق الأجهزة المنزلية الذكية: شبكة Wi-Fi، وشبكة Bluetooth منخفضة الطاقة', 6110.00, 30005, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F55NBlxMpzsWhatsApp%20Image%E2%80%8F%202025-01-22%20at%2019.06.06.jpeg?alt=media&token=85f52cea-64de-4807-97d8-ed53ea304d81", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FEqfxC9T9361.avif?alt=media&token=5cf1ba8a-9a2d-42d7-b4ec-bbaea3eb06e5", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FFMxftVorMU2.avif?alt=media&token=002d6f08-b429-449d-b590-53b79ec8b5dd", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F3tZfMb9XWe3.avif?alt=media&token=f01e0e74-af18-48c3-81cc-78cd0f8cda89", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fyms3DNdFg84.avif?alt=media&token=c9dc1057-038a-4317-bc81-88168963c916", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2F2I3LQNrgLL5.avif?alt=media&token=3e007b87-85bb-4418-ad1f-beeb72be4908", "https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2Fz2kQdIrYN86.avif?alt=media&token=59cce502-c460-4ac4-804a-74ac20f1d319"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
INSERT INTO products (id, name, name_ar, description, price, category_id, image_url, images, is_active) VALUES (30001, 'Camera', NULL, '• \\\\\\\\\\\\كاميرا تويا الذكية واي فاي 2 ميجابكسل • •⁠ ⁠العدسة القياسية: 3.6 ملم • •⁠ ⁠الصوت في اتجاهين وقطع الأشعة تحت الحمراء • •⁠ ⁠مسافة الرؤية الليلية: 8-10 م • يشمل مصدر الطاقة: 5 فولت، 1 أمبير • •⁠ ⁠بدون منفذ RJ45 • •⁠ ⁠الحد الأقصى لدعم سيارة 128G TF', 3660.00, 30001, NULL, '["https://firebasestorage.googleapis.com/v0/b/neat-planet-378416-live/o/project_assets%2F10165%2Fimages%2Fproducts%2FTWLN7Qq71SWhatsApp%20Image%E2%80%8F%202025-01-22%20at%2019.18.16.jpeg?alt=media&token=c4509514-bc94-4c34-8c61-001a7d90af9d"]', 1) ON DUPLICATE KEY UPDATE name=VALUES(name), name_ar=VALUES(name_ar), description=VALUES(description), price=VALUES(price), image_url=VALUES(image_url);
